import type { CareerQuestion } from "./pharmacy-tech-questions-extended";

export const pharmacyTechQuestionsBatch3: CareerQuestion[] = [
  {"id":"ptcb-1056","stem":"What is the generic name for Ozempic?","options":["Liraglutide","Dulaglutide","Semaglutide","Exenatide"],"correctIndex":2,"rationale":"Semaglutide is the generic name for Ozempic (injection) and Rybelsus (oral), a GLP-1 receptor agonist for type 2 diabetes and weight management (Wegovy). Liraglutide is Victoza/Saxenda, dulaglutide is Trulicity, and exenatide is Byetta/Bydureon.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1057","stem":"What is the proper angle for subcutaneous injection?","options":["15 degrees","45 degrees","90 degrees","Both 45 and 90 degrees depending on the patient"],"correctIndex":3,"rationale":"Subcutaneous injections are given at 45 or 90 degrees depending on the patient's body habitus and the needle length. Thin patients or short needles use 45 degrees; average/obese patients with standard needles use 90 degrees. Intradermal injections are at 10-15 degrees.","difficulty":2,"category":"Pharmacology","topic":"injection techniques"},
  {"id":"ptcb-1058","stem":"Which of the following is a potassium-sparing diuretic?","options":["Furosemide","Hydrochlorothiazide","Spironolactone","Bumetanide"],"correctIndex":2,"rationale":"Spironolactone (Aldactone) is a potassium-sparing diuretic that blocks aldosterone receptors. Unlike loop diuretics (furosemide, bumetanide) and thiazides (HCTZ) which cause potassium loss, spironolactone retains potassium. Risk of hyperkalemia exists, especially with ACE inhibitors or ARBs.","difficulty":1,"category":"Drug Classifications","topic":"diuretic classes"},
  {"id":"ptcb-1059","stem":"What is the purpose of a pharmacy's quality improvement (QI) program?","options":["To increase prescription volume","To systematically monitor and improve patient care processes","To reduce staff hours","To negotiate better drug prices"],"correctIndex":1,"rationale":"Quality improvement programs use systematic approaches (PDSA cycles, root cause analysis) to identify problems, implement changes, and measure outcomes to continuously improve patient safety and medication use processes.","difficulty":2,"category":"Medication Safety","topic":"quality improvement","certification":"PTCB"},
  {"id":"ptcb-1060","stem":"A vial of insulin contains 10 mL at a concentration of 100 units/mL. How many total units are in the vial?","options":["100 units","500 units","1,000 units","10,000 units"],"correctIndex":2,"rationale":"Total units = Volume × Concentration = 10 mL × 100 units/mL = 1,000 units. Standard insulin vials contain 10 mL of U-100 insulin (100 units/mL). This is important for calculating how many vials a patient needs for a given period based on their daily dose.","difficulty":1,"category":"Dosage Calculations","topic":"insulin calculations"},
  {"id":"ptcb-1061","stem":"Which medication is the first-line treatment for Clostridioides difficile (C. diff) infection?","options":["Metronidazole","Vancomycin (oral)","Ciprofloxacin","Amoxicillin"],"correctIndex":1,"rationale":"Oral vancomycin is first-line for initial C. diff infection per current guidelines (formerly, metronidazole was preferred for mild cases). IV vancomycin is NOT effective for C. diff because it doesn't reach the GI lumen. Fidaxomicin (Dificid) is an alternative first-line option.","difficulty":2,"category":"Pharmacology","topic":"infectious disease treatment"},
  {"id":"ptcb-1062","stem":"What is the purpose of USP <800>?","options":["Standards for non-sterile compounding","Standards for sterile compounding","Standards for handling hazardous drugs","Standards for pharmacy management"],"correctIndex":2,"rationale":"USP <800> establishes standards for safe handling of hazardous drugs to minimize exposure to healthcare workers. It covers receiving, storage, compounding, dispensing, administration, and disposal of hazardous drugs. It requires engineering controls, PPE, medical surveillance, and spill management.","difficulty":1,"category":"Patient Safety","topic":"USP standards"},
  {"id":"ptcb-1063","stem":"What is the brand name for aripiprazole?","options":["Risperdal","Abilify","Seroquel","Zyprexa"],"correctIndex":1,"rationale":"Aripiprazole is sold as Abilify, an atypical antipsychotic used for schizophrenia, bipolar disorder, and adjunct therapy for depression. Risperdal is risperidone, Seroquel is quetiapine, and Zyprexa is olanzapine. Aripiprazole is a partial dopamine agonist with a unique mechanism.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1064","stem":"A pharmacy needs to prepare 200 g of a 5% ointment using a 10% ointment and white petrolatum (0%). How many grams of the 10% ointment are needed?","options":["50 g","100 g","150 g","175 g"],"correctIndex":1,"rationale":"Using alligation: 10% ointment gets |5-0| = 5 parts. 0% petrolatum gets |5-10| = 5 parts. Ratio is 5:5 = 1:1, so equal amounts. For 200 g total: 200 ÷ 2 = 100 g of each. Mix 100 g of 10% ointment with 100 g of white petrolatum to get 200 g of 5%.","difficulty":2,"category":"Dosage Calculations","topic":"alligation"},
  {"id":"ptcb-1065","stem":"Which drug class carries a risk of rhabdomyolysis?","options":["ACE inhibitors","Statins","Proton pump inhibitors","Beta-blockers"],"correctIndex":1,"rationale":"Statins can cause myopathy (muscle pain/weakness) and rarely rhabdomyolysis (severe muscle breakdown that can cause kidney failure). Risk increases with high doses, CYP3A4 inhibitors, gemfibrozil, and renal impairment. Patients should report unexplained muscle pain. CK levels may be monitored.","difficulty":2,"category":"Pharmacology","topic":"drug adverse effects"},
  {"id":"ptcb-1066","stem":"What does 'PRN' mean on a prescription?","options":["Immediately","Every day","As needed","Before meals"],"correctIndex":2,"rationale":"PRN stands for 'pro re nata,' meaning as needed or as the situation arises. PRN medications are taken only when symptoms occur, not on a scheduled basis. Common PRN medications include pain relievers, anti-nausea drugs, and rescue inhalers. Day supply for PRN uses the maximum daily dose.","difficulty":1,"category":"Prescription Processing","topic":"sig codes"},
  {"id":"ptcb-1067","stem":"Which of the following is an anticholinergic medication used for overactive bladder?","options":["Tamsulosin","Oxybutynin","Finasteride","Sildenafil"],"correctIndex":1,"rationale":"Oxybutynin (Ditropan) is an anticholinergic/antimuscarinic used for overactive bladder and urinary incontinence. Tamsulosin is an alpha-blocker for BPH, finasteride is a 5-alpha reductase inhibitor for BPH, and sildenafil (Viagra) is a PDE5 inhibitor for erectile dysfunction.","difficulty":2,"category":"Drug Classifications","topic":"urologic medications"},
  {"id":"ptcb-1068","stem":"A technician discovers a medication has been recalled. What is the first step?","options":["Continue dispensing until stock runs out","Pull the affected lot numbers from shelves immediately","Wait for the pharmacist to return from lunch","Notify the manufacturer before taking action"],"correctIndex":1,"rationale":"The first step upon learning of a recall is to immediately pull all affected lot numbers from shelves and quarantine them to prevent dispensing. Then notify the pharmacist, check if any affected products were recently dispensed to patients, and follow the recall procedures for return or destruction.","difficulty":1,"category":"Quality Assurance","topic":"recall procedures"},
  {"id":"ptcb-1069","stem":"What is the generic name for Humira?","options":["Infliximab","Adalimumab","Etanercept","Certolizumab"],"correctIndex":1,"rationale":"Adalimumab is the generic name for Humira, a TNF-alpha inhibitor (monoclonal antibody, '-mab' suffix) used for rheumatoid arthritis, psoriasis, Crohn's disease, and other autoimmune conditions. Infliximab is Remicade, etanercept is Enbrel, and certolizumab is Cimzia.","difficulty":2,"category":"Pharmacology","topic":"biologic medications"},
  {"id":"ptcb-1070","stem":"A prescription reads: 'Prednisolone 15 mg/5 mL, 1 tsp bid x 5 days, then 1/2 tsp bid x 5 days.' How many mL should be dispensed?","options":["50 mL","75 mL","100 mL","150 mL"],"correctIndex":1,"rationale":"First 5 days: 5 mL (1 tsp) × 2 (bid) × 5 days = 50 mL. Next 5 days: 2.5 mL (1/2 tsp) × 2 (bid) × 5 days = 25 mL. Total = 50 + 25 = 75 mL. Steroid taper calculations require careful reading of the sig to determine total volume needed.","difficulty":2,"category":"Dosage Calculations","topic":"taper calculations"},
  {"id":"ptcb-1071","stem":"Which medication requires the clozapine REMS program for dispensing?","options":["Olanzapine","Clozapine","Risperidone","Quetiapine"],"correctIndex":1,"rationale":"Clozapine (Clozaril) requires enrollment in the Clozapine REMS Program due to the risk of severe neutropenia (agranulocytosis). ANC (absolute neutrophil count) monitoring is mandatory before each dispensing. If ANC drops below threshold, clozapine must be discontinued immediately.","difficulty":2,"category":"Regulations/Law","topic":"REMS programs"},
  {"id":"ptcb-1072","stem":"What does a 'Quantity Limit' mean in prescription insurance?","options":["The pharmacy can only order limited quantities","The maximum amount of medication covered per fill or time period","The patient can only take a limited number of pills","The drug is being discontinued"],"correctIndex":1,"rationale":"A quantity limit is an insurance restriction that caps the amount of medication covered per fill or time period (e.g., 30 tablets per 30 days, or 9 tablets per month for triptan medications). This controls costs and prevents overuse. Exceptions may be obtained via prior authorization.","difficulty":1,"category":"Pharmacy Operations","topic":"insurance restrictions"},
  {"id":"ptcb-1073","stem":"Which of the following is a calcium channel blocker used specifically for heart rate control?","options":["Amlodipine","Nifedipine","Diltiazem","Felodipine"],"correctIndex":2,"rationale":"Diltiazem (Cardizem) is a non-dihydropyridine CCB that slows heart rate and reduces blood pressure. It's used for rate control in atrial fibrillation. Amlodipine, nifedipine, and felodipine are dihydropyridine CCBs ('-dipine' suffix) that primarily affect blood vessels, not heart rate.","difficulty":2,"category":"Drug Classifications","topic":"CCB subclasses"},
  {"id":"ptcb-1074","stem":"How should reconstituted powdered medications typically be labeled?","options":["With only the original label","With date of reconstitution, BUD, concentration, storage conditions, and initials","With just the expiration date","No additional labeling required"],"correctIndex":1,"rationale":"Reconstituted medications must be labeled with the date of reconstitution, beyond-use date (BUD), final concentration after reconstitution, required storage conditions (usually refrigerate), and the initials of the person who reconstituted it. The original label remains in place.","difficulty":1,"category":"Compounding","topic":"labeling requirements"},
  {"id":"ptcb-1075","stem":"Which of the following is true about Schedule V controlled substances?","options":["They have no refills allowed","They can only be prescribed by specialists","They have the lowest abuse potential among controlled substances","They require a DEA Form 222 to order"],"correctIndex":2,"rationale":"Schedule V substances have the lowest abuse potential of all controlled substances. Examples include cough preparations with small amounts of codeine, pregabalin, and some antidiarrheal preparations. They may be refilled up to 5 times within 6 months. Form 222 is only for C-I and C-II.","difficulty":1,"category":"Regulations/Law","topic":"controlled substance schedules"},
  {"id":"ptcb-1076","stem":"A patient uses insulin glargine 30 units daily. How many 10 mL vials (U-100) are needed for a 90-day supply?","options":["1 vial","2 vials","3 vials","4 vials"],"correctIndex":2,"rationale":"Daily dose: 30 units. For 90 days: 30 × 90 = 2,700 units. Each vial: 10 mL × 100 units/mL = 1,000 units. Vials needed: 2,700 ÷ 1,000 = 2.7, rounded up to 3 vials. Always round up when calculating supply to ensure the patient doesn't run short.","difficulty":2,"category":"Dosage Calculations","topic":"insulin supply calculations"},
  {"id":"ptcb-1077","stem":"What is 'medication reconciliation'?","options":["Returning expired medications to the manufacturer","Comparing a patient's current medications with newly ordered medications","Counting controlled substances","Reconciling the pharmacy cash register"],"correctIndex":1,"rationale":"Medication reconciliation is the process of comparing a patient's current medication list with newly ordered medications at each transition of care (admission, transfer, discharge). It identifies discrepancies — omissions, duplications, interactions, and dose changes — to prevent errors.","difficulty":1,"category":"Patient Safety","topic":"medication reconciliation"},
  {"id":"ptcb-1078","stem":"Which of the following medications is a DPP-4 inhibitor?","options":["Canagliflozin","Sitagliptin","Liraglutide","Metformin"],"correctIndex":1,"rationale":"Sitagliptin (Januvia) is a DPP-4 inhibitor ('-gliptin' suffix) that increases incretin levels, stimulating insulin release and reducing glucagon. DPP-4 inhibitors are weight-neutral and well-tolerated. Canagliflozin is an SGLT2-i, liraglutide is a GLP-1 RA, and metformin is a biguanide.","difficulty":2,"category":"Drug Classifications","topic":"diabetes drug classes"},
  {"id":"ptcb-1079","stem":"What is the proper storage for nitroglycerin sublingual tablets?","options":["Refrigerator","Room temperature in original amber glass bottle","Freezer","Any plastic container"],"correctIndex":1,"rationale":"Nitroglycerin SL tablets must be stored at room temperature in the original amber glass container with the metal screw cap tightly closed. Light, heat, moisture, and plastic degrade nitroglycerin. Opened bottles should be replaced every 6 months. Cotton should be removed from the bottle after opening.","difficulty":2,"category":"Pharmacy Operations","topic":"special storage"},
  {"id":"ptcb-1080","stem":"Which abbreviation is on the ISMP 'Do Not Use' list?","options":["tid","bid","U (for units)","mL"],"correctIndex":2,"rationale":"'U' for units is on the ISMP Do Not Use abbreviation list because it can be mistaken for '0' (zero), '4', or 'cc,' leading to 10-fold dosing errors. The correct practice is to write 'units' in full. Other Do Not Use items include 'IU,' 'QD,' 'QOD,' trailing zeros, and lack of leading zeros.","difficulty":1,"category":"Medication Safety","topic":"error-prone abbreviations"},
  {"id":"ptcb-1081","stem":"A patient takes Synthroid 88 mcg daily. What is the daily dose in mg?","options":["0.088 mg","0.88 mg","8.8 mg","88 mg"],"correctIndex":0,"rationale":"To convert mcg to mg, divide by 1,000: 88 mcg ÷ 1,000 = 0.088 mg. Levothyroxine is commonly prescribed in mcg, making this conversion important. Confusion between mcg and mg is a common error source; 88 mg would be a massive overdose.","difficulty":1,"category":"Dosage Calculations","topic":"unit conversions"},
  {"id":"ptcb-1082","stem":"What type of drug interaction occurs when one drug increases the metabolism of another through enzyme induction?","options":["Pharmacodynamic interaction","Pharmacokinetic interaction","Idiosyncratic interaction","Synergistic interaction"],"correctIndex":1,"rationale":"Enzyme induction is a pharmacokinetic interaction affecting drug metabolism. When one drug induces CYP450 enzymes (e.g., rifampin induces CYP3A4), it increases the metabolism of other drugs processed by that enzyme, reducing their blood levels and efficacy. This differs from pharmacodynamic interactions that affect drug effects at the receptor level.","difficulty":2,"category":"Drug Interactions","topic":"pharmacokinetic interactions"},
  {"id":"ptcb-1083","stem":"What is the generic name for Victoza?","options":["Semaglutide","Dulaglutide","Liraglutide","Exenatide"],"correctIndex":2,"rationale":"Liraglutide is the generic name for Victoza (diabetes) and Saxenda (weight management), a GLP-1 receptor agonist administered as a daily subcutaneous injection. Semaglutide is Ozempic/Wegovy, dulaglutide is Trulicity, and exenatide is Byetta/Bydureon.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1084","stem":"When performing IV push calculations, 1 mL is approximately how many drops using a standard macrodrip set (20 gtt/mL)?","options":["10 drops","15 drops","20 drops","60 drops"],"correctIndex":2,"rationale":"With a 20 gtt/mL macrodrip set, 1 mL equals 20 drops. Common drop factors are 10, 15, and 20 gtt/mL for macrodrip, and 60 gtt/mL for microdrip. The drop factor is printed on the IV tubing packaging and is essential for drip rate calculations.","difficulty":1,"category":"Dosage Calculations","topic":"drop factor"},
  {"id":"ptcb-1085","stem":"Which of the following is a common sign of digoxin toxicity?","options":["Hyperglycemia","Visual disturbances (yellow-green halos)","Elevated blood pressure","Weight gain"],"correctIndex":1,"rationale":"Digoxin toxicity can cause visual disturbances (yellow-green halos around lights, blurred vision), nausea, vomiting, anorexia, fatigue, and potentially fatal cardiac arrhythmias. Digoxin has a narrow therapeutic index (0.5-2.0 ng/mL). Hypokalemia increases toxicity risk.","difficulty":2,"category":"Pharmacology","topic":"drug toxicity"},
  {"id":"ptcb-1086","stem":"What is the proper procedure for transferring a controlled substance prescription?","options":["Any pharmacy staff can transfer it by phone","A pharmacist must perform the transfer; C-III to C-V can only be transferred once (federally)","Controlled substances cannot be transferred","Transfers can be done by fax only"],"correctIndex":1,"rationale":"Federally, C-III through C-V prescriptions can be transferred one time between pharmacies, and the transfer must be communicated between pharmacists. C-II prescriptions cannot be transferred. Some states allow additional transfers if pharmacies share a real-time online database. Complete documentation is required.","difficulty":2,"category":"Regulations/Law","topic":"prescription transfers"},
  {"id":"ptcb-1087","stem":"A 2.5% hydrocortisone cream is equivalent to how many mg per gram?","options":["2.5 mg/g","25 mg/g","250 mg/g","0.25 mg/g"],"correctIndex":1,"rationale":"A 2.5% cream means 2.5 g per 100 g, which equals 25 mg per gram (2.5 g/100 g = 2,500 mg/100 g = 25 mg/g). Percentage w/w means grams of drug per 100 grams of preparation. This conversion is essential for compounding calculations.","difficulty":2,"category":"Dosage Calculations","topic":"percentage w/w"},
  {"id":"ptcb-1088","stem":"Which of the following is an H2 receptor antagonist?","options":["Omeprazole","Famotidine","Sucralfate","Misoprostol"],"correctIndex":1,"rationale":"Famotidine (Pepcid) is an H2 receptor antagonist ('-tidine' suffix) that reduces gastric acid by blocking histamine H2 receptors on parietal cells. It's less potent than PPIs. Omeprazole is a PPI, sucralfate is a mucosal protectant, and misoprostol is a prostaglandin analog.","difficulty":1,"category":"Drug Classifications","topic":"GI drug classes"},
  {"id":"ptcb-1089","stem":"What is the significance of a 'black box warning' on a drug?","options":["The drug is available only by mail order","It is the FDA's strongest safety warning about serious or life-threatening risks","The drug is being recalled","The drug requires refrigeration"],"correctIndex":1,"rationale":"A black box warning (boxed warning) is the FDA's most stringent warning, indicating the drug carries serious or life-threatening risks. Examples include suicidality with antidepressants, bleeding with anticoagulants, and hepatotoxicity with certain medications. It appears in a bordered box at the top of the prescribing information.","difficulty":1,"category":"Patient Safety","topic":"FDA warnings"},
  {"id":"ptcb-1090","stem":"How should a pharmacy technician respond to a patient who is upset about a long wait time?","options":["Ignore the patient until they calm down","Acknowledge their frustration, apologize for the wait, and provide an estimated time","Argue that the pharmacy is very busy","Tell them to go to another pharmacy"],"correctIndex":1,"rationale":"The technician should acknowledge the patient's frustration empathetically, apologize for the wait, and provide a realistic time estimate. Offering to help prioritize an urgent prescription or suggesting they return later shows customer service skills. Arguing or dismissing concerns escalates the situation.","difficulty":1,"category":"Patient Communication","topic":"conflict resolution"},
  {"id":"ptcb-1091","stem":"What is the trade name for the combination drug lisinopril-hydrochlorothiazide?","options":["Lotrel","Zestoretic","Diovan HCT","Benicar HCT"],"correctIndex":1,"rationale":"Zestoretic is the brand name for lisinopril-hydrochlorothiazide, combining an ACE inhibitor with a thiazide diuretic for hypertension. Lotrel is amlodipine-benazepril, Diovan HCT is valsartan-HCTZ, and Benicar HCT is olmesartan-HCTZ.","difficulty":2,"category":"Pharmacology","topic":"combination drugs"},
  {"id":"ptcb-1092","stem":"Which of the following vaccines is a live attenuated vaccine?","options":["Influenza (injectable)","MMR (measles, mumps, rubella)","Hepatitis B","Pneumococcal conjugate"],"correctIndex":1,"rationale":"MMR is a live attenuated vaccine and is contraindicated in immunocompromised patients and pregnant women. Other live vaccines include varicella, rotavirus, live attenuated influenza (nasal), and zoster (Zostavax, discontinued). Injectable influenza, hepatitis B, and pneumococcal conjugate are inactivated vaccines.","difficulty":2,"category":"Pharmacology","topic":"vaccine types"},
  {"id":"ptcb-1093","stem":"A pharmacy receives a shipment with an average wholesale temperature of 15°C during transport. Which products may be affected?","options":["Room temperature medications only","Refrigerated medications (2-8°C)","Frozen medications only","No products are affected"],"correctIndex":1,"rationale":"Medications requiring refrigeration (2-8°C) would be affected by transport at 15°C, as this exceeds their required storage range. The pharmacy should quarantine affected products, document the temperature excursion, and contact the manufacturer to determine if the products remain usable.","difficulty":2,"category":"Inventory Management","topic":"cold chain management"},
  {"id":"ptcb-1094","stem":"Which drug is commonly used as a prokinetic agent to increase GI motility?","options":["Ondansetron","Metoclopramide","Loperamide","Bismuth subsalicylate"],"correctIndex":1,"rationale":"Metoclopramide (Reglan) is a prokinetic agent that increases GI motility by acting as a dopamine D2 antagonist and serotonin 5-HT4 agonist. It's used for gastroparesis and GERD. It carries a black box warning for tardive dyskinesia with prolonged use. Ondansetron is an antiemetic, and loperamide slows motility.","difficulty":2,"category":"Pharmacology","topic":"GI medications"},
  {"id":"ptcb-1095","stem":"What does the term 'adjudication' mean in pharmacy?","options":["The legal process of settling drug disputes","The electronic process of submitting and receiving a response from insurance","The act of compounding a prescription","A quality assurance review"],"correctIndex":1,"rationale":"Adjudication is the real-time electronic process where a prescription claim is submitted to the patient's insurance, processed against their benefits, and a response is returned (paid, rejected, or requiring action). Common rejection codes include refill-too-soon, prior authorization required, and non-formulary drug.","difficulty":2,"category":"Pharmacy Operations","topic":"insurance claims"},
  {"id":"ptcb-1096","stem":"Which of the following is a macrolide antibiotic?","options":["Ciprofloxacin","Amoxicillin","Azithromycin","Doxycycline"],"correctIndex":2,"rationale":"Azithromycin (Zithromax, Z-Pack) is a macrolide antibiotic ('-mycin' or '-thromycin' suffix) effective against respiratory and soft tissue infections. Ciprofloxacin is a fluoroquinolone, amoxicillin is a penicillin, and doxycycline is a tetracycline. Macrolides inhibit bacterial protein synthesis.","difficulty":1,"category":"Drug Classifications","topic":"antibiotic classes"},
  {"id":"ptcb-1097","stem":"A patient is prescribed warfarin 5 mg on Mon, Wed, Fri, and 2.5 mg on Tue, Thu, Sat, Sun. What is the total weekly dose?","options":["22.5 mg","25 mg","27.5 mg","35 mg"],"correctIndex":2,"rationale":"Mon+Wed+Fri: 5 mg × 3 days = 15 mg. Tue+Thu+Sat+Sun: 2.5 mg × 4 days = 10 mg. Total weekly dose = 15 + 10 = 27.5 mg. Warfarin dosing often varies by day to achieve precise weekly doses for INR management.","difficulty":2,"category":"Dosage Calculations","topic":"variable dosing calculations"},
  {"id":"ptcb-1098","stem":"What is the primary function of the anteroom in a sterile compounding facility?","options":["Drug storage area","Transition area for hand hygiene and garbing before entering the buffer room","Patient consultation area","Administrative office"],"correctIndex":1,"rationale":"The anteroom (ante-area, ISO Class 8 or better) serves as a transition zone between the uncontrolled environment and the buffer room. Personnel perform hand hygiene, don garbing attire, and prepare supplies before entering the cleaner buffer room. This staged approach minimizes contamination.","difficulty":2,"category":"Sterile Products","topic":"cleanroom design"},
  {"id":"ptcb-1099","stem":"Which drug requires dose adjustment based on renal function (CrCl)?","options":["Lisinopril","Gabapentin","Amlodipine","Atorvastatin"],"correctIndex":1,"rationale":"Gabapentin is primarily renally eliminated and requires dose reduction in patients with decreased creatinine clearance (CrCl). Failure to adjust doses can cause excessive sedation and toxicity. Lisinopril is also renally cleared but usually needs adjustment only in severe impairment. Amlodipine and atorvastatin are hepatically metabolized.","difficulty":2,"category":"Pharmacology","topic":"renal dose adjustment"},
  {"id":"ptcb-1100","stem":"What is the Cockcroft-Gault equation used to estimate?","options":["Body surface area","Creatinine clearance","Drug half-life","Cardiac output"],"correctIndex":1,"rationale":"The Cockcroft-Gault equation estimates creatinine clearance (CrCl), a measure of kidney function used for drug dose adjustments. The formula uses age, weight, serum creatinine, and sex. CrCl = [(140 - age) × weight] / (72 × SCr), multiplied by 0.85 for females.","difficulty":3,"category":"Dosage Calculations","topic":"renal function calculations"},
  {"id":"ptcb-1101","stem":"Which of the following is NOT on the ISMP high-alert medication list for community/ambulatory settings?","options":["Metformin","Warfarin","Insulin","Opioids"],"correctIndex":0,"rationale":"Metformin is NOT on the ISMP high-alert medication list. High-alert medications for community/ambulatory settings include insulin, opioids, anticoagulants (warfarin), hypoglycemic agents (sulfonylureas, but not metformin specifically), and others that carry heightened risk of significant harm when used in error.","difficulty":2,"category":"Patient Safety","topic":"high-alert medications"},
  {"id":"ptcb-1102","stem":"What is the trade name for tadalafil?","options":["Viagra","Cialis","Levitra","Stendra"],"correctIndex":1,"rationale":"Tadalafil is sold as Cialis (erectile dysfunction and BPH) and Adcirca (pulmonary arterial hypertension). Viagra is sildenafil, Levitra is vardenafil, and Stendra is avanafil. All are PDE5 inhibitors. Tadalafil has the longest duration of action (up to 36 hours).","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1103","stem":"A technician prepares a compound and spills some on the counter. The spilled material contains a hazardous drug. What should be done first?","options":["Wipe it up with a paper towel","Don appropriate PPE from the spill kit","Continue working and clean up later","Call 911"],"correctIndex":1,"rationale":"For hazardous drug spills, the first step is to don appropriate PPE from the spill kit (double chemo-tested gloves, gown, face/eye protection, respirator if needed). Then contain and clean the spill using the spill kit materials. Never clean hazardous drug spills without proper PPE. Document the incident.","difficulty":2,"category":"Patient Safety","topic":"hazardous drug spills"},
  {"id":"ptcb-1104","stem":"Which drug is used to reverse the effects of benzodiazepines?","options":["Naloxone","Flumazenil","Protamine","Atropine"],"correctIndex":1,"rationale":"Flumazenil (Romazicon) is a benzodiazepine antagonist that reverses the sedative effects of benzodiazepines by competitively blocking GABA-A receptors. Naloxone reverses opioids, protamine reverses heparin, and atropine treats cholinergic toxicity/bradycardia. Flumazenil can precipitate seizures in chronic benzodiazepine users.","difficulty":2,"category":"Pharmacology","topic":"antidotes"},
  {"id":"ptcb-1105","stem":"How many mL are in 1 pint?","options":["240 mL","360 mL","473 mL","946 mL"],"correctIndex":2,"rationale":"1 pint = 473 mL (approximately 480 mL is sometimes used). 1 quart = 946 mL. 1 gallon = 3,785 mL. These volume conversions are important for dispensing liquid medications, especially when the prescription is written using household or apothecary measures.","difficulty":2,"category":"Dosage Calculations","topic":"volume conversions"},
  {"id":"ptcb-1106","stem":"Which drug class ends in '-sartan'?","options":["ACE inhibitors","ARBs (Angiotensin II Receptor Blockers)","Beta-blockers","Calcium channel blockers"],"correctIndex":1,"rationale":"The '-sartan' suffix identifies angiotensin II receptor blockers (ARBs) such as losartan, valsartan, irbesartan, and candesartan. ARBs block AT1 receptors, preventing angiotensin II from causing vasoconstriction. They don't cause the dry cough associated with ACE inhibitors ('-pril' suffix).","difficulty":1,"category":"Drug Classifications","topic":"drug class suffixes"},
  {"id":"ptcb-1107","stem":"What is the correct procedure when a pharmacist is not available and a patient needs an emergency supply of a chronic medication?","options":["The technician can dispense a 30-day supply","Refuse to dispense any medication","Dispense a small emergency supply per state law (where permitted) and document it","Tell the patient to go to the emergency room"],"correctIndex":2,"rationale":"Some states allow pharmacists (and in limited cases, trained technicians under specific protocols) to provide a small emergency supply of chronic maintenance medications when the prescriber is unreachable. The exact quantity and documentation requirements vary by state law. This prevents gaps in essential therapy.","difficulty":3,"category":"Pharmacy Operations","topic":"emergency dispensing"},
  {"id":"ptcb-1108","stem":"Which of the following is a common side effect of metformin?","options":["Weight gain","GI upset (nausea, diarrhea)","Hypoglycemia when used alone","Edema"],"correctIndex":1,"rationale":"GI upset (nausea, diarrhea, abdominal pain) is the most common side effect of metformin, affecting up to 25% of patients. Extended-release formulations reduce GI side effects. Metformin is weight-neutral or causes slight weight loss. It rarely causes hypoglycemia when used alone because it doesn't stimulate insulin secretion.","difficulty":1,"category":"Pharmacology","topic":"drug side effects"},
  {"id":"ptcb-1109","stem":"When must a pharmacy technician wash their hands during sterile compounding?","options":["Only at the beginning of the shift","Before each new compounding session, after breaks, after touching non-sterile items","Only when visibly soiled","Hand washing is not required if gloves are worn"],"correctIndex":1,"rationale":"Hand washing with antimicrobial soap for at least 30 seconds is required before each compounding session, after breaks, after touching non-sterile items, before re-gloving, and when re-entering the compounding area. Gloves alone are insufficient — proper hand hygiene is the foundation of aseptic technique.","difficulty":1,"category":"Sterile Products","topic":"aseptic technique"},
  {"id":"ptcb-1110","stem":"What does the abbreviation 'BIN' stand for in pharmacy insurance?","options":["Bank Identification Number","Billing Identification Number","Benefit Insurance Number","Batch Inventory Number"],"correctIndex":0,"rationale":"BIN stands for Bank Identification Number (also called IIN - Issuer Identification Number), a 6-digit number on the patient's insurance card that routes the electronic prescription claim to the correct PBM or insurance processor. Along with PCN and Group, it's essential for claim submission.","difficulty":2,"category":"Pharmacy Operations","topic":"insurance processing"},
  {"id":"ptcb-1111","stem":"Which medication has a narrow therapeutic index and requires regular blood level monitoring?","options":["Amoxicillin","Lithium","Metformin","Ibuprofen"],"correctIndex":1,"rationale":"Lithium (Lithobid) has a narrow therapeutic index (0.6-1.2 mEq/L for maintenance; up to 1.5 for acute mania) and requires regular serum level monitoring. Toxicity can cause tremor, confusion, renal impairment, and cardiac arrhythmias. Other narrow TI drugs include warfarin, phenytoin, digoxin, and theophylline.","difficulty":2,"category":"Pharmacology","topic":"therapeutic drug monitoring"},
  {"id":"ptcb-1112","stem":"A patient needs 50 mg/kg/day of cephalexin divided q6h. The patient weighs 44 lb. The suspension is 250 mg/5 mL. What is each dose in mL?","options":["2.5 mL","5 mL","10 mL","12.5 mL"],"correctIndex":1,"rationale":"Step 1: 44 lb ÷ 2.2 = 20 kg. Step 2: Daily dose = 50 mg/kg × 20 kg = 1,000 mg/day. Step 3: q6h = 4 doses/day, so each dose = 1,000 ÷ 4 = 250 mg. Step 4: Volume = (250 mg × 5 mL) ÷ 250 mg = 5 mL per dose.","difficulty":2,"category":"Dosage Calculations","topic":"pediatric weight-based dosing"},
  {"id":"ptcb-1113","stem":"What is the purpose of a 'sentinel event' investigation in pharmacy?","options":["To discipline the staff member responsible","To investigate an unexpected event resulting in death or serious harm and prevent recurrence","To increase pharmacy revenue","To reduce inventory costs"],"correctIndex":1,"rationale":"A sentinel event is an unexpected occurrence involving death or serious physical/psychological injury. Investigation uses root cause analysis (RCA) to identify systemic factors, not to assign blame. The goal is to implement system-level changes to prevent recurrence — a 'just culture' approach.","difficulty":2,"category":"Quality Assurance","topic":"sentinel events"},
  {"id":"ptcb-1114","stem":"Which of the following is the correct definition of 'bioavailability'?","options":["The rate at which a drug is manufactured","The fraction of an administered drug that reaches systemic circulation unchanged","The total amount of drug in a dosage form","The shelf life of a medication"],"correctIndex":1,"rationale":"Bioavailability is the fraction (percentage) of an administered drug dose that reaches systemic circulation in unchanged form. IV drugs have 100% bioavailability. Oral drugs have reduced bioavailability due to first-pass metabolism, incomplete absorption, and degradation. Bioequivalence of generics is based on comparable bioavailability.","difficulty":2,"category":"Pharmacology","topic":"pharmacokinetics"},
  {"id":"ptcb-1115","stem":"What is the brand name for quetiapine?","options":["Abilify","Risperdal","Seroquel","Zyprexa"],"correctIndex":2,"rationale":"Quetiapine is sold as Seroquel, an atypical antipsychotic used for schizophrenia, bipolar disorder, and major depressive disorder (adjunct). Abilify is aripiprazole, Risperdal is risperidone, and Zyprexa is olanzapine. Quetiapine is commonly prescribed and has sedating properties.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1116","stem":"Which cleaning agent is recommended for cleaning laminar airflow workbenches?","options":["Tap water","70% isopropyl alcohol","Bleach only","Soap and water"],"correctIndex":1,"rationale":"70% isopropyl alcohol (IPA) is the standard cleaning agent for LAFWs, cleaned using lint-free wipes in a side-to-side motion starting from the back. Sterile 70% IPA is used for the work surface. Some facilities also use a sporicidal agent periodically. Tap water and soap would introduce contaminants.","difficulty":1,"category":"Sterile Products","topic":"cleanroom cleaning"},
  {"id":"ptcb-1117","stem":"A patient asks about the difference between Tylenol and Advil. The pharmacy technician should:","options":["Explain the differences in detail","Refer the patient to the pharmacist for OTC counseling","Tell the patient both are the same","Recommend Tylenol for everyone"],"correctIndex":1,"rationale":"Questions about medication differences, recommendations, and which product is more appropriate are clinical questions that should be directed to the pharmacist. Even for OTC medications, the technician's scope does not include making therapeutic recommendations or comparing drug efficacy.","difficulty":1,"category":"Patient Communication","topic":"OTC counseling referral"},
  {"id":"ptcb-1118","stem":"Which of the following is a tetracycline antibiotic?","options":["Azithromycin","Ciprofloxacin","Doxycycline","Amoxicillin"],"correctIndex":2,"rationale":"Doxycycline is a tetracycline antibiotic ('-cycline' suffix) used for respiratory infections, acne, Lyme disease, and STIs. It should not be taken with dairy products or antacids (chelation). Other tetracyclines include minocycline and tetracycline. Azithromycin is a macrolide, ciprofloxacin is a fluoroquinolone.","difficulty":1,"category":"Drug Classifications","topic":"antibiotic classes"},
  {"id":"ptcb-1119","stem":"What is the concentration (mg/mL) of a 0.5% solution?","options":["0.5 mg/mL","5 mg/mL","50 mg/mL","500 mg/mL"],"correctIndex":1,"rationale":"A 0.5% (w/v) solution contains 0.5 g per 100 mL = 500 mg per 100 mL = 5 mg/mL. The conversion factor is: 1% = 10 mg/mL. So 0.5% × 10 = 5 mg/mL. This conversion is frequently tested on the PTCB and used daily in pharmacy practice.","difficulty":2,"category":"Dosage Calculations","topic":"percentage to mg/mL"},
  {"id":"ptcb-1120","stem":"What is the primary concern with abruptly discontinuing beta-blockers?","options":["Hypotension","Rebound hypertension and tachycardia","Constipation","Weight gain"],"correctIndex":1,"rationale":"Abruptly stopping beta-blockers can cause rebound hypertension, tachycardia, and angina due to upregulation of beta-receptors during chronic therapy. The dose should be gradually tapered over 1-2 weeks. This is especially important for patients with coronary artery disease who may experience MI.","difficulty":2,"category":"Pharmacology","topic":"drug discontinuation"},
  {"id":"ptcb-1121","stem":"Which organization accredits compounding pharmacies?","options":["DEA","FDA","PCAB (Pharmacy Compounding Accreditation Board)","ASHP"],"correctIndex":2,"rationale":"PCAB (Pharmacy Compounding Accreditation Board) provides voluntary accreditation for compounding pharmacies, verifying compliance with USP standards and best practices. State boards of pharmacy license pharmacies, the FDA regulates drug manufacturing, and ASHP accredits pharmacy residency programs.","difficulty":2,"category":"Quality Assurance","topic":"pharmacy accreditation"},
  {"id":"ptcb-1122","stem":"What is the generic name for Entresto?","options":["Valsartan","Losartan-HCTZ","Sacubitril-valsartan","Amlodipine-valsartan"],"correctIndex":2,"rationale":"Sacubitril-valsartan is the generic for Entresto, a neprilysin inhibitor/ARB combination (ARNI) used for heart failure with reduced ejection fraction. It reduces hospitalization and mortality in HFrEF. Patients must have a 36-hour washout from ACE inhibitors before starting due to angioedema risk.","difficulty":2,"category":"Pharmacology","topic":"heart failure medications"},
  {"id":"ptcb-1123","stem":"What is the beyond-use date for a Category 1 compounded sterile preparation (CSP) prepared in an ISO Class 5 PEC with no further testing?","options":["1 hour","12 hours","24 hours at controlled room temperature or 3 days refrigerated","30 days refrigerated"],"correctIndex":1,"rationale":"Per USP <797> (revised), Category 1 CSPs prepared with aseptic conditions in an ISO Class 5 PEC have a BUD of 12 hours at controlled room temperature or 24 hours refrigerated when no sterility testing is performed. Longer BUDs require Category 2 conditions and additional testing.","difficulty":3,"category":"Sterile Products","topic":"CSP beyond-use dating"},
  {"id":"ptcb-1124","stem":"Which lab value is used to monitor long-term blood glucose control in diabetic patients?","options":["Fasting blood glucose","Hemoglobin A1C (HbA1c)","Random blood glucose","Oral glucose tolerance test"],"correctIndex":1,"rationale":"HbA1c reflects average blood glucose over the past 2-3 months by measuring the percentage of glycated hemoglobin. Target is generally <7% for most diabetics. Fasting glucose reflects a single point in time. HbA1c is the standard for monitoring long-term glycemic control and adjusting therapy.","difficulty":1,"category":"Pharmacology","topic":"diabetes monitoring"},
  {"id":"ptcb-1125","stem":"A prescription reads: 'Fluticasone nasal spray, 1 spray each nostril bid.' The bottle contains 120 sprays. What is the day supply?","options":["15 days","30 days","60 days","120 days"],"correctIndex":1,"rationale":"Daily sprays = 1 spray × 2 nostrils × 2 times (bid) = 4 sprays/day. Day supply = 120 sprays ÷ 4 sprays/day = 30 days. Nasal spray day supply calculations require counting sprays per nostril per dose.","difficulty":2,"category":"Dosage Calculations","topic":"nasal spray day supply"},
  {"id":"ptcb-1126","stem":"What is the primary purpose of a material safety data sheet (SDS)?","options":["To list drug prices","To provide chemical hazard and safety information","To document pharmacy inventory","To track prescription refills"],"correctIndex":1,"rationale":"A Safety Data Sheet (SDS, formerly MSDS) provides detailed information about chemical hazards, handling procedures, exposure risks, first aid measures, and disposal requirements. SDSs are required by OSHA for all hazardous chemicals in the workplace and must be readily accessible to pharmacy staff.","difficulty":1,"category":"Patient Safety","topic":"workplace safety"},
  {"id":"ptcb-1127","stem":"Which of the following is a sulfonylurea used to treat type 2 diabetes?","options":["Metformin","Glipizide","Pioglitazone","Acarbose"],"correctIndex":1,"rationale":"Glipizide (Glucotrol) is a sulfonylurea ('-ide' suffix for second-generation: glipizide, glyburide, glimepiride) that stimulates insulin secretion from pancreatic beta cells. Key side effect: hypoglycemia (especially in elderly and renal impairment). Sulfonylureas also cause weight gain. Metformin is a biguanide.","difficulty":1,"category":"Drug Classifications","topic":"diabetes drug classes"},
  {"id":"ptcb-1128","stem":"A pharmacy technician accidentally gives a patient the wrong medication. After notifying the pharmacist, what documentation is required?","options":["No documentation needed","Complete an incident/error report detailing the event","Write a letter to the patient's physician","File a police report"],"correctIndex":1,"rationale":"After notifying the pharmacist (who assesses clinical impact and contacts the patient if needed), an incident/error report must be completed. The report documents what happened, contributing factors, and corrective actions. This supports the quality improvement program and is used to prevent similar errors.","difficulty":1,"category":"Medication Safety","topic":"error documentation"},
  {"id":"ptcb-1129","stem":"What is the brand name for carvedilol?","options":["Lopressor","Tenormin","Coreg","Bystolic"],"correctIndex":2,"rationale":"Carvedilol is sold as Coreg, a non-selective beta-blocker with alpha-1 blocking activity, used for heart failure, hypertension, and post-MI. Lopressor is metoprolol tartrate, Tenormin is atenolol, and Bystolic is nebivolol. Carvedilol's dual mechanism provides both heart rate and blood pressure reduction.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1130","stem":"What is an 'e-prescribing' system?","options":["A system for emailing patients their prescriptions","Electronic transmission of prescription information from prescriber to pharmacy","An online pharmacy website","Electronic counting machines"],"correctIndex":1,"rationale":"E-prescribing (electronic prescribing) is the electronic transmission of prescription information directly from the prescriber's EHR to the pharmacy's dispensing system. Benefits include reduced errors from illegible handwriting, real-time formulary checking, automatic allergy screening, and faster processing. EPCS allows electronic prescribing of controlled substances.","difficulty":1,"category":"Pharmacy Operations","topic":"pharmacy technology"},
  {"id":"ptcb-1131","stem":"Which of the following drugs can cause photosensitivity?","options":["Metformin","Doxycycline","Lisinopril","Gabapentin"],"correctIndex":1,"rationale":"Doxycycline (tetracycline) commonly causes photosensitivity — increased susceptibility to sunburn. Patients should avoid prolonged sun exposure, use sunscreen (SPF 30+), and wear protective clothing. Other photosensitizing drugs include fluoroquinolones, sulfonamides, thiazides, and amiodarone.","difficulty":2,"category":"Pharmacology","topic":"drug-induced photosensitivity"},
  {"id":"ptcb-1132","stem":"How should a pharmacy handle a 'short-dated' medication that will expire within 3 months?","options":["Return it to the manufacturer immediately","Move it to the front of the shelf (FIFO) and consider returning to wholesaler if returnable","Dispose of it immediately","Continue dispensing without any changes"],"correctIndex":1,"rationale":"Short-dated medications should be moved to the front of the shelf per FIFO principles and flagged for priority dispensing. Many wholesalers accept returns of medications within 6 months of expiration through reverse distribution companies. The pharmacy should not dispose of usable medications prematurely.","difficulty":2,"category":"Inventory Management","topic":"short-dated medications"},
  {"id":"ptcb-1133","stem":"What is the dose of epinephrine administered via auto-injector (EpiPen) for adults?","options":["0.15 mg","0.3 mg","0.5 mg","1 mg"],"correctIndex":1,"rationale":"The adult EpiPen delivers 0.3 mg (0.3 mL of 1:1000) of epinephrine via IM injection into the outer thigh. EpiPen Jr. delivers 0.15 mg for pediatric patients (15-30 kg). Epinephrine is the first-line treatment for anaphylaxis and should be administered immediately.","difficulty":1,"category":"Pharmacology","topic":"emergency medications"},
  {"id":"ptcb-1134","stem":"When a prescription is received for a medication that is not on the patient's insurance formulary, the technician should:","options":["Fill it at full price without telling the patient","Inform the pharmacist who may contact the prescriber for a formulary alternative or submit a PA","Tell the patient to switch insurance","Refuse to process the prescription"],"correctIndex":1,"rationale":"The technician should inform the pharmacist about the non-formulary rejection. The pharmacist may contact the prescriber to suggest a formulary alternative, initiate a prior authorization, or discuss cash price options with the patient. The goal is ensuring the patient receives appropriate therapy.","difficulty":1,"category":"Pharmacy Operations","topic":"formulary management"},
  {"id":"ptcb-1135","stem":"Which of the following medications is classified as a benzodiazepine?","options":["Buspirone","Hydroxyzine","Lorazepam","Gabapentin"],"correctIndex":2,"rationale":"Lorazepam (Ativan) is a benzodiazepine (Schedule IV) used for anxiety, insomnia, seizures, and procedural sedation. Benzodiazepines enhance GABA activity. Buspirone is a non-benzodiazepine anxiolytic, hydroxyzine is an antihistamine with anxiolytic properties, and gabapentin is an anticonvulsant.","difficulty":1,"category":"Drug Classifications","topic":"anxiolytic classes"},
  {"id":"ptcb-1136","stem":"A prescription for eye drops reads: '1 gtt os q4h prn redness.' What does 'os' mean?","options":["Right eye","Left eye","Both eyes","Right ear"],"correctIndex":1,"rationale":"'OS' (oculus sinister) means left eye. 'OD' (oculus dexter) means right eye. 'OU' (oculus uterque) means both eyes. Note: ISMP recommends writing 'left eye,' 'right eye,' or 'both eyes' to avoid confusion with 'AS' (left ear), 'AD' (right ear), 'AU' (both ears).","difficulty":1,"category":"Prescription Processing","topic":"ophthalmic abbreviations"},
  {"id":"ptcb-1137","stem":"What does the Mosteller formula calculate?","options":["Creatinine clearance","Body surface area (BSA)","Ideal body weight","Drug half-life"],"correctIndex":1,"rationale":"The Mosteller formula calculates Body Surface Area (BSA): BSA (m²) = √[(height cm × weight kg) ÷ 3600]. BSA is used for dosing chemotherapy and some pediatric drugs. The Cockcroft-Gault equation calculates CrCl, and the Devine formula estimates ideal body weight.","difficulty":3,"category":"Dosage Calculations","topic":"BSA calculations"},
  {"id":"ptcb-1138","stem":"Which of the following is an antiplatelet medication?","options":["Warfarin","Heparin","Clopidogrel","Enoxaparin"],"correctIndex":2,"rationale":"Clopidogrel (Plavix) is an antiplatelet agent that inhibits ADP-induced platelet aggregation. It's used to prevent thrombotic events in patients with recent MI, stroke, or peripheral arterial disease. Warfarin is an anticoagulant, heparin and enoxaparin are also anticoagulants. Antiplatelets and anticoagulants have different mechanisms.","difficulty":2,"category":"Drug Classifications","topic":"antiplatelet vs anticoagulant"},
  {"id":"ptcb-1139","stem":"What is the primary purpose of 'bar code medication administration' (BCMA)?","options":["To speed up pharmacy dispensing","To verify the right patient receives the right medication at the right time","To track pharmacy inventory","To print prescription labels"],"correctIndex":1,"rationale":"BCMA uses barcode scanning at the bedside to verify the 'five rights': right patient, right drug, right dose, right route, and right time. The nurse scans the patient's wristband and medication barcode before administration. Studies show BCMA reduces medication administration errors by 50-80%.","difficulty":1,"category":"Medication Safety","topic":"technology-based safety"},
  {"id":"ptcb-1140","stem":"What is the generic name for Rybelsus?","options":["Dulaglutide","Liraglutide","Semaglutide","Exenatide"],"correctIndex":2,"rationale":"Rybelsus contains oral semaglutide, the first oral GLP-1 receptor agonist for type 2 diabetes. Must be taken on an empty stomach with no more than 4 oz of plain water, 30 minutes before food. Ozempic is injectable semaglutide.","difficulty":2,"category":"Pharmacology","topic":"diabetes medications","certification":"PTCB"},
  {"id":"ptcb-1141","stem":"A compound requires 2.5 g of active ingredient. The balance has a minimum weighable quantity of 120 mg. Can the ingredient be weighed directly?","options":["No, it is below the MWQ","Yes, 2.5 g exceeds the MWQ of 120 mg","Only if a more sensitive balance is available","It depends on the type of compound"],"correctIndex":1,"rationale":"2.5 g = 2,500 mg, which greatly exceeds the MWQ of 120 mg. The ingredient can be weighed directly on the Class III prescription balance. MWQ limitations only apply when the amount needed is close to or below 120 mg, requiring serial dilution techniques.","difficulty":1,"category":"Compounding","topic":"weighing accuracy"},
  {"id":"ptcb-1142","stem":"Which federal agency enforces the Controlled Substances Act?","options":["FDA","DEA","FTC","CDC"],"correctIndex":1,"rationale":"The DEA (Drug Enforcement Administration) enforces the Controlled Substances Act (CSA), which regulates the manufacture, distribution, and dispensing of controlled substances. The FDA approves drugs and monitors safety. The FTC regulates advertising. The CDC focuses on disease prevention.","difficulty":1,"category":"Regulations/Law","topic":"regulatory agencies"},
  {"id":"ptcb-1143","stem":"A 1 L bag of D5NS (5% dextrose in 0.9% NaCl) contains how many grams of dextrose?","options":["5 g","9 g","50 g","59 g"],"correctIndex":2,"rationale":"D5 means 5% dextrose = 5 g per 100 mL. In 1 L (1000 mL): 5 g/100 mL × 1000 mL = 50 g dextrose. The NS component adds 9 g NaCl (0.9% × 1000 mL), but the question asks only about dextrose. The total solute content is 59 g (50 g dextrose + 9 g NaCl).","difficulty":2,"category":"Dosage Calculations","topic":"IV solution content"},
  {"id":"ptcb-1144","stem":"Which medication is commonly used to prevent organ transplant rejection?","options":["Methotrexate","Tacrolimus","Prednisone","Azithromycin"],"correctIndex":1,"rationale":"Tacrolimus (Prograf) is a calcineurin inhibitor immunosuppressant used to prevent organ transplant rejection. It has a narrow therapeutic index requiring blood level monitoring. Prednisone is also used in transplant regimens but is not the primary immunosuppressant. Methotrexate is for autoimmune diseases and cancer.","difficulty":2,"category":"Pharmacology","topic":"immunosuppressants"},
  {"id":"ptcb-1145","stem":"What should a pharmacy technician do if they suspect a prescription is forged?","options":["Fill it and investigate later","Alert the pharmacist immediately","Call the police without telling anyone","Confront the patient"],"correctIndex":1,"rationale":"If a technician suspects a forged prescription (altered quantities, suspicious DEA number, unfamiliar prescriber, unusual patient behavior), they should immediately alert the pharmacist discreetly. The pharmacist will verify the prescription by contacting the prescriber's office. Never confront the patient directly.","difficulty":1,"category":"Prescription Processing","topic":"forged prescriptions"},
  {"id":"ptcb-1146","stem":"Which of the following is an alpha-1 blocker used for benign prostatic hyperplasia (BPH)?","options":["Finasteride","Tamsulosin","Oxybutynin","Sildenafil"],"correctIndex":1,"rationale":"Tamsulosin (Flomax) is a selective alpha-1A blocker ('-osin' suffix) that relaxes smooth muscle in the prostate and bladder neck, improving urine flow in BPH. Finasteride is a 5-alpha reductase inhibitor (shrinks prostate), oxybutynin treats OAB, and sildenafil treats ED.","difficulty":2,"category":"Drug Classifications","topic":"BPH medications"},
  {"id":"ptcb-1147","stem":"What is a 'look-back' period in pharmacy insurance?","options":["How far back insurance checks for duplicate fills","The time between refills","The period for returning medications","The manufacturer's warranty period"],"correctIndex":0,"rationale":"A look-back period is the timeframe insurance systems review to check for duplicate fills, early refills, and utilization patterns. For example, if a 30-day supply was filled 20 days ago, the look-back would reject an early refill. This prevents duplicate dispensing and potential drug diversion.","difficulty":2,"category":"Pharmacy Operations","topic":"insurance adjudication"},
  {"id":"ptcb-1148","stem":"Which of the following best describes 'first-pass metabolism'?","options":["The first dose of a new medication","Drug metabolism in the liver before reaching systemic circulation","Metabolism that occurs during IV administration","Drug breakdown in the stomach"],"correctIndex":1,"rationale":"First-pass metabolism (first-pass effect) occurs when orally administered drugs are metabolized by the liver before entering systemic circulation, reducing bioavailability. Drugs with high first-pass metabolism (morphine, nitroglycerin) may need higher oral doses or alternative routes (sublingual, transdermal, IV).","difficulty":2,"category":"Pharmacology","topic":"pharmacokinetics"},
  {"id":"ptcb-1149","stem":"What is the brand name for buprenorphine/naloxone?","options":["Narcan","Suboxone","Vivitrol","Sublocade"],"correctIndex":1,"rationale":"Buprenorphine/naloxone is sold as Suboxone (sublingual film or tablet), used for opioid use disorder treatment. Buprenorphine is a partial opioid agonist; naloxone deters IV misuse. Narcan is naloxone alone, Vivitrol is naltrexone injection, and Sublocade is buprenorphine extended-release injection.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1150","stem":"Which of the following is the correct sequence for aseptic hand washing in sterile compounding?","options":["5-second rinse, apply soap, 10-second scrub","Wet hands, apply antimicrobial soap, scrub for at least 30 seconds, rinse, dry with lint-free towel","Apply hand sanitizer only","Quick rinse under warm water"],"correctIndex":1,"rationale":"Proper aseptic hand washing requires wetting hands with warm water, applying antimicrobial soap, scrubbing all surfaces (including between fingers and under nails) for at least 30 seconds, rinsing thoroughly, and drying with a lint-free towel. This must be done before every compounding session.","difficulty":1,"category":"Sterile Products","topic":"hand hygiene technique"},
  {"id":"ptcb-1151","stem":"Which of the following is an antiemetic that works by blocking serotonin (5-HT3) receptors?","options":["Promethazine","Ondansetron","Metoclopramide","Dimenhydrinate"],"correctIndex":1,"rationale":"Ondansetron (Zofran) is a 5-HT3 receptor antagonist ('-setron' suffix) used to prevent nausea and vomiting, especially chemotherapy-induced. Promethazine blocks histamine and dopamine, metoclopramide blocks dopamine, and dimenhydrinate (Dramamine) is an antihistamine.","difficulty":2,"category":"Drug Classifications","topic":"antiemetic classes"},
  {"id":"ptcb-1152","stem":"What is the most important step before dispensing any medication?","options":["Checking the price","Verifying the pharmacist has checked the prescription","Placing it in a bag","Adding the receipt"],"correctIndex":1,"rationale":"The most critical step before dispensing is ensuring the pharmacist has verified the prescription (drug, dose, directions, interactions, patient allergies). This final check is the last safety barrier before the medication reaches the patient. Dispensing without pharmacist verification is illegal and dangerous.","difficulty":1,"category":"Medication Safety","topic":"verification process"},
  {"id":"ptcb-1153","stem":"A prescription reads: 'Lisinopril 10 mg #90, 1 tab daily.' What is the day supply?","options":["30 days","60 days","90 days","180 days"],"correctIndex":2,"rationale":"Day supply = Quantity ÷ Daily dose = 90 tabs ÷ 1 tab/day = 90 days. This is a straightforward day supply calculation for a once-daily medication. The day supply determines refill dates and is essential for insurance billing.","difficulty":1,"category":"Dosage Calculations","topic":"day supply"},
  {"id":"ptcb-1154","stem":"Which hormone does levothyroxine replace?","options":["Insulin","Estrogen","Thyroid hormone (T4)","Cortisol"],"correctIndex":2,"rationale":"Levothyroxine (Synthroid) is a synthetic form of thyroxine (T4), used to replace thyroid hormone in patients with hypothyroidism. T4 is converted to the active T3 in the body. Proper dosing requires regular TSH monitoring. Levothyroxine is one of the most prescribed medications in the US.","difficulty":1,"category":"Pharmacology","topic":"endocrine medications"},
  {"id":"ptcb-1155","stem":"What is the significance of lot numbers on medication packaging?","options":["They indicate the price","They enable tracking of specific batches for recall purposes","They show the drug's generic name","They indicate the drug schedule"],"correctIndex":1,"rationale":"Lot numbers identify specific production batches, enabling pharmacies to quickly identify and pull affected products during recalls. They also provide traceability for quality control, expiration tracking, and adverse event investigations. Every medication container must have a lot number and expiration date.","difficulty":1,"category":"Inventory Management","topic":"lot tracking"},
  {"id":"ptcb-1156","stem":"Which antidepressant has a unique mechanism as a norepinephrine-dopamine reuptake inhibitor (NDRI)?","options":["Sertraline","Venlafaxine","Bupropion","Mirtazapine"],"correctIndex":2,"rationale":"Bupropion (Wellbutrin for depression, Zyban for smoking cessation) is an NDRI that inhibits the reuptake of norepinephrine and dopamine. Unlike SSRIs, it does not cause sexual dysfunction or weight gain — it may actually cause weight loss. It's also used for smoking cessation.","difficulty":2,"category":"Pharmacology","topic":"antidepressant mechanisms"},
  {"id":"ptcb-1157","stem":"What does 'tiw' mean in prescription directions?","options":["Three times a day","Three times a week","Twice a week","Two times daily"],"correctIndex":1,"rationale":"'tiw' means three times a week (not three times a day, which is 'tid'). However, 'tiw' is on the ISMP error-prone abbreviation list because it can be confused with 'tid' (three times daily) or 'biw' (twice weekly). It's recommended to write out 'three times weekly' instead.","difficulty":2,"category":"Prescription Processing","topic":"error-prone abbreviations"},
  {"id":"ptcb-1158","stem":"Which PPE component protects against aerosol exposure during hazardous drug compounding?","options":["Standard surgical mask","N95 respirator or powered air-purifying respirator","Safety glasses only","Standard latex gloves"],"correctIndex":1,"rationale":"For activities that may generate aerosols of hazardous drugs (outside a BSC), an N95 respirator or PAPR is required. Standard surgical masks do not filter drug aerosols. Within a properly functioning BSC, respiratory protection is generally not needed due to the cabinet's containment.","difficulty":2,"category":"Patient Safety","topic":"respiratory protection"},
  {"id":"ptcb-1159","stem":"What is the generic name for Adderall?","options":["Methylphenidate","Amphetamine/dextroamphetamine","Lisdexamfetamine","Atomoxetine"],"correctIndex":1,"rationale":"Adderall contains mixed amphetamine salts (amphetamine/dextroamphetamine), a Schedule II stimulant for ADHD and narcolepsy. Methylphenidate is Ritalin/Concerta, lisdexamfetamine is Vyvanse, and atomoxetine (Strattera) is a non-stimulant ADHD medication.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1160","stem":"A pharmacy uses an automatic counting machine. What is the most important maintenance task?","options":["Painting it regularly","Cleaning between different medications to prevent cross-contamination","Replacing it every month","Running it empty daily"],"correctIndex":1,"rationale":"Automatic counting machines must be cleaned between different medications to prevent cross-contamination and potential allergic reactions. Penicillin residue on an uncleaned machine could contaminate subsequent fills. Machines should have dedicated counting cells for high-risk drugs like penicillins and sulfonamides.","difficulty":1,"category":"Pharmacy Operations","topic":"equipment maintenance"},
  {"id":"ptcb-1161","stem":"Which statin does NOT require dose adjustment with renal impairment?","options":["Atorvastatin","Rosuvastatin","Simvastatin","Pravastatin"],"correctIndex":0,"rationale":"Atorvastatin (Lipitor) is hepatically metabolized and does not require dose adjustment for renal impairment. Rosuvastatin requires reduced starting doses in severe renal impairment. Atorvastatin's hepatic metabolism makes it a preferred statin for patients with kidney disease.","difficulty":3,"category":"Pharmacology","topic":"renal dosing considerations"},
  {"id":"ptcb-1162","stem":"What type of mortar is preferred for mixing liquids or making solutions?","options":["Wedgwood (porcelain)","Glass","Wooden","Ceramic"],"correctIndex":1,"rationale":"A glass mortar is preferred for mixing liquids, solutions, and suspensions because glass is non-porous and does not absorb or stain. Wedgwood (porcelain) mortars are more abrasive and better suited for grinding/triturating powders. Glass mortars allow easy visualization of the preparation.","difficulty":2,"category":"Compounding","topic":"compounding equipment selection"},
  {"id":"ptcb-1163","stem":"Which drug requires baseline and periodic liver function tests (LFTs)?","options":["Amlodipine","Atorvastatin","Lisinopril","Metoprolol"],"correctIndex":1,"rationale":"Statins including atorvastatin can cause hepatotoxicity, and baseline LFTs should be obtained before starting therapy. Periodic monitoring is recommended, especially if the patient develops symptoms of liver injury (unexplained fatigue, jaundice, dark urine). If ALT exceeds 3× ULN, discontinuation should be considered.","difficulty":2,"category":"Pharmacology","topic":"drug monitoring"},
  {"id":"ptcb-1164","stem":"What does 'STAT' mean when written on a prescription or medication order?","options":["Standard treatment","Immediately/at once","Schedule twice a day","Stop all treatment"],"correctIndex":1,"rationale":"STAT (from Latin 'statim') means immediately or at once. A STAT order has the highest priority and must be filled and administered as quickly as possible. In hospital settings, STAT medications are typically dispensed within 15-30 minutes.","difficulty":1,"category":"Prescription Processing","topic":"priority designations"},
  {"id":"ptcb-1165","stem":"Which of the following is a direct Factor Xa inhibitor?","options":["Warfarin","Dabigatran","Rivaroxaban","Heparin"],"correctIndex":2,"rationale":"Rivaroxaban (Xarelto) is a direct Factor Xa inhibitor, part of the DOAC class. Other Factor Xa inhibitors include apixaban (Eliquis) and edoxaban (Savaysa). Dabigatran (Pradaxa) is a direct thrombin (Factor IIa) inhibitor. Warfarin inhibits vitamin K-dependent factors, and heparin works through antithrombin III.","difficulty":2,"category":"Drug Classifications","topic":"anticoagulant mechanisms"},
  {"id":"ptcb-1166","stem":"A patient using a fluticasone/salmeterol (Advair) inhaler should be counseled to:","options":["Use it as a rescue inhaler","Rinse mouth after each use to prevent oral thrush","Take it only when symptomatic","Double the dose if a dose is missed"],"correctIndex":1,"rationale":"Inhaled corticosteroids (like fluticasone in Advair) can cause oral candidiasis (thrush) and hoarseness. Rinsing the mouth and spitting after each use significantly reduces this risk. Advair is a maintenance inhaler, not a rescue inhaler, and should be used regularly regardless of symptoms.","difficulty":2,"category":"Patient Communication","topic":"inhaler counseling"},
  {"id":"ptcb-1167","stem":"What is the purpose of a 'negative pressure room' in a pharmacy?","options":["To store refrigerated drugs","To compound hazardous drugs safely","To increase air circulation for comfort","To reduce electricity costs"],"correctIndex":1,"rationale":"A negative pressure room maintains air pressure lower than surrounding areas, so air flows into the room (not out), preventing hazardous drug vapors from escaping to adjacent areas. This is required per USP <800> for compounding hazardous drugs. Non-hazardous sterile compounding uses positive pressure rooms.","difficulty":2,"category":"Sterile Products","topic":"room pressure differentials"},
  {"id":"ptcb-1168","stem":"What is the generic name for Proair HFA?","options":["Levalbuterol","Albuterol","Formoterol","Salmeterol"],"correctIndex":1,"rationale":"Albuterol is the generic name for ProAir HFA, Ventolin HFA, and Proventil HFA — short-acting beta-2 agonist (SABA) inhalers used as rescue inhalers for acute bronchospasm. Levalbuterol is Xopenex, formoterol is a LABA, and salmeterol is also a LABA.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1169","stem":"How often should the primary engineering control (LAFW or BSC) be certified?","options":["Monthly","Every 6 months","Annually","Every 2 years"],"correctIndex":1,"rationale":"Per USP <797>, LAFWs and BSCs must be certified at least every 6 months, and whenever moved, repaired, or the HEPA filter is replaced. Certification includes airflow velocity testing, HEPA filter integrity testing (DOP/PAO test), and particle count verification.","difficulty":2,"category":"Sterile Products","topic":"PEC certification"},
  {"id":"ptcb-1170","stem":"Which opioid is available as a transdermal patch?","options":["Morphine","Oxycodone","Fentanyl","Hydromorphone"],"correctIndex":2,"rationale":"Fentanyl is available as a transdermal patch (Duragesic) for continuous pain management in opioid-tolerant patients. The patch provides 72 hours of pain control. It's NOT for opioid-naïve patients or acute pain due to risk of fatal respiratory depression. Used patches must be folded adhesive-to-adhesive and disposed properly.","difficulty":1,"category":"Pharmacology","topic":"opioid formulations"},
  {"id":"ptcb-1171","stem":"A new prescription has the quantity listed as '1/2 gallon.' How many mL should be dispensed?","options":["946 mL","1,893 mL","2,365 mL","3,785 mL"],"correctIndex":1,"rationale":"1 gallon = 3,785 mL (approximately 3,840 mL by some references). Half gallon = 3,785 ÷ 2 = approximately 1,893 mL. This household-to-metric conversion may be seen with bulk liquid prescriptions like lactulose or polyethylene glycol solutions.","difficulty":2,"category":"Dosage Calculations","topic":"volume conversions"},
  {"id":"ptcb-1172","stem":"What is the primary risk of combining two CNS depressants?","options":["Insomnia","Hypertension","Excessive sedation and respiratory depression","Hyperactivity"],"correctIndex":2,"rationale":"Combining CNS depressants (opioids, benzodiazepines, alcohol, muscle relaxants, sedating antihistamines) increases the risk of excessive sedation, respiratory depression, coma, and death. This additive/synergistic effect is a major cause of drug-related fatalities. Black box warnings exist for opioid-benzodiazepine combinations.","difficulty":1,"category":"Drug Interactions","topic":"CNS depressant combinations"},
  {"id":"ptcb-1173","stem":"What is the standard concentration of heparin used for IV line flushing?","options":["1 unit/mL","10 units/mL","100 units/mL","1,000 units/mL"],"correctIndex":2,"rationale":"Heparin flush solutions typically contain 10 or 100 units/mL. The 100 units/mL concentration is commonly used for flushing central venous catheters. Note: Confusion between heparin flush (100 units/mL) and therapeutic heparin (1,000 or 10,000 units/mL) has caused fatal overdoses — this is an ISMP high-alert concern.","difficulty":2,"category":"Sterile Products","topic":"heparin flush"},
  {"id":"ptcb-1174","stem":"Which vitamin should be supplemented when taking isoniazid (INH) for tuberculosis?","options":["Vitamin A","Vitamin B6 (pyridoxine)","Vitamin C","Vitamin D"],"correctIndex":1,"rationale":"Isoniazid depletes pyridoxine (vitamin B6) and can cause peripheral neuropathy. Supplementation with vitamin B6 (25-50 mg daily) is recommended, especially for patients at higher risk: malnourished, pregnant, diabetic, HIV-positive, or elderly. This is a commonly tested drug-nutrient interaction.","difficulty":2,"category":"Drug Interactions","topic":"drug-nutrient interactions"},
  {"id":"ptcb-1175","stem":"What is the trade name for celecoxib?","options":["Mobic","Celebrex","Voltaren","Feldene"],"correctIndex":1,"rationale":"Celecoxib is sold as Celebrex, a selective COX-2 inhibitor NSAID. It has lower GI bleeding risk compared to non-selective NSAIDs but carries cardiovascular risk (black box warning). Mobic is meloxicam, Voltaren is diclofenac, and Feldene is piroxicam — all non-selective NSAIDs.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1176","stem":"What does 'par level' mean in pharmacy inventory management?","options":["The maximum amount of stock allowed","The predetermined minimum quantity that triggers reordering","The exact quantity to order each time","The amount of expired stock"],"correctIndex":1,"rationale":"Par level is the minimum inventory threshold for each product. When stock falls to or below par level, it triggers a reorder. Par levels are set based on usage patterns, lead times, and desired safety stock. Effective par level management prevents both stockouts and overstock situations.","difficulty":1,"category":"Inventory Management","topic":"par level management"},
  {"id":"ptcb-1177","stem":"Which of the following medications is an opioid antagonist used for opioid overdose reversal?","options":["Buprenorphine","Methadone","Naloxone","Tramadol"],"correctIndex":2,"rationale":"Naloxone (Narcan) is a pure opioid antagonist that rapidly reverses opioid overdose by competitively blocking mu-opioid receptors. It's available as nasal spray and injection. Buprenorphine is a partial agonist, methadone is a full agonist used for maintenance, and tramadol is a weak opioid analgesic.","difficulty":1,"category":"Pharmacology","topic":"opioid reversal"},
  {"id":"ptcb-1178","stem":"A prescription for ophthalmic drops reads: 'gtt i od q2h while awake.' If the patient is awake 16 hours/day and the bottle contains 300 drops, what is the day supply?","options":["25 days","37.5 days","50 days","75 days"],"correctIndex":1,"rationale":"Drops per day = 1 drop × every 2 hours × 16 hours awake = 8 drops/day. Day supply = 300 drops ÷ 8 drops/day = 37.5 days. For insurance, this would typically be rounded down to 37 days. Note: 'od' means right eye (oculus dexter).","difficulty":3,"category":"Dosage Calculations","topic":"ophthalmic day supply"},
  {"id":"ptcb-1179","stem":"Which of the following best describes 'therapeutic duplication'?","options":["Taking the same drug twice","Taking two drugs from the same therapeutic class simultaneously","Refilling a prescription twice in one month","Having two prescribers for the same condition"],"correctIndex":1,"rationale":"Therapeutic duplication occurs when a patient takes two or more drugs from the same therapeutic class (e.g., two different SSRIs, or both lisinopril and enalapril). This increases side effect risk without additional benefit. DUR screening should flag therapeutic duplication during prescription processing.","difficulty":1,"category":"Quality Assurance","topic":"therapeutic duplication"},
  {"id":"ptcb-1180","stem":"What is the brand name for the combination inhaler fluticasone/vilanterol?","options":["Advair","Symbicort","Breo Ellipta","Dulera"],"correctIndex":2,"rationale":"Breo Ellipta contains fluticasone furoate/vilanterol (ICS/LABA) for once-daily maintenance in asthma and COPD. Advair is fluticasone/salmeterol, Symbicort is budesonide/formoterol, and Dulera is mometasone/formoterol. All are ICS/LABA combinations but differ in dosing frequency and device type.","difficulty":2,"category":"Pharmacology","topic":"combination inhalers"},
  {"id":"ptcb-1181","stem":"What is the purpose of a 'Drug Take-Back' program?","options":["To recycle medication containers","To provide safe disposal of unused or expired medications","To return defective drugs to manufacturers","To exchange brand drugs for generics"],"correctIndex":1,"rationale":"Drug Take-Back programs provide safe, convenient disposal of unused and expired medications. They prevent environmental contamination (from flushing or trash disposal), accidental poisoning, and drug diversion. The DEA sponsors National Drug Take-Back Days, and many pharmacies have permanent collection bins.","difficulty":1,"category":"Pharmacy Operations","topic":"medication disposal"},
  {"id":"ptcb-1182","stem":"Which drug interaction necessitates avoiding tyramine-rich foods?","options":["SSRIs","MAO inhibitors","Beta-blockers","ACE inhibitors"],"correctIndex":1,"rationale":"MAO inhibitors (phenelzine, tranylcypromine) prevent the breakdown of tyramine, a pressor amine found in aged cheeses, cured meats, fermented foods, and draft beer. Excess tyramine can cause a hypertensive crisis (severe headache, stroke). This is one of the most dangerous food-drug interactions.","difficulty":2,"category":"Drug Interactions","topic":"MAOI-tyramine interaction"},
  {"id":"ptcb-1183","stem":"What is the difference between 'dispense' and 'administer' in pharmacy terminology?","options":["They mean the same thing","Dispensing is providing the drug to the patient; administering is giving/applying the drug to the patient","Dispensing is for OTC; administering is for Rx","Dispensing is hospital-only; administering is retail-only"],"correctIndex":1,"rationale":"Dispensing involves preparing, packaging, and providing medication to the patient or caregiver for later self-administration. Administering means directly giving or applying the medication to the patient (injection, applying ointment, etc.). Hospital pharmacies often prepare medications for nurses to administer.","difficulty":1,"category":"Pharmacy Operations","topic":"pharmacy terminology"},
  {"id":"ptcb-1184","stem":"Which of the following is a sign that an IV admixture may be contaminated?","options":["The solution is clear and colorless","The solution appears cloudy, contains precipitate, or has color change","The volume is exactly as specified","The label is intact"],"correctIndex":1,"rationale":"Signs of contamination or incompatibility in IV admixtures include cloudiness, turbidity, precipitate formation, color change, gas bubbles, or particulate matter. Any IV preparation showing these signs must be discarded and not administered. Visual inspection is a critical safety check before dispensing or administering IV products.","difficulty":1,"category":"Sterile Products","topic":"visual inspection"},
  {"id":"ptcb-1185","stem":"How many mg of NaCl are in 100 mL of half-normal saline (0.45% NaCl)?","options":["45 mg","450 mg","900 mg","4,500 mg"],"correctIndex":1,"rationale":"Half-normal saline is 0.45% NaCl = 0.45 g per 100 mL = 450 mg per 100 mL. Normal saline (0.9%) would contain 900 mg per 100 mL. These concentration calculations are fundamental for IV solution preparation and pharmacy math.","difficulty":2,"category":"Dosage Calculations","topic":"w/v percentage calculations"},
  {"id":"ptcb-1186","stem":"Which organization sets standards for pharmacy compounding in the United States?","options":["FDA","DEA","USP (United States Pharmacopeia)","APhA"],"correctIndex":2,"rationale":"USP (United States Pharmacopeia) establishes compounding standards through its chapters: <795> for non-sterile compounding, <797> for sterile compounding, and <800> for hazardous drug handling. These are legally enforceable standards that pharmacies must follow. The FDA regulates drug manufacturing, not pharmacy compounding.","difficulty":1,"category":"Compounding","topic":"regulatory standards"},
  {"id":"ptcb-1187","stem":"What is the generic name for Brilinta?","options":["Clopidogrel","Prasugrel","Ticagrelor","Ticlopidine"],"correctIndex":2,"rationale":"Ticagrelor is the generic name for Brilinta, an antiplatelet P2Y12 inhibitor used to reduce thrombotic events in acute coronary syndrome. Unlike clopidogrel (Plavix), ticagrelor is a reversible inhibitor. It must be taken with low-dose aspirin (81 mg) but NOT with aspirin doses >100 mg.","difficulty":2,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1188","stem":"What type of water is used for reconstituting oral suspensions?","options":["Sterile water for injection","Distilled water","Purified water USP","Tap water"],"correctIndex":2,"rationale":"Purified Water USP is used for reconstituting oral suspensions. It meets USP standards for purity but does not need to be sterile since it's for oral use. Sterile Water for Injection is reserved for parenteral preparations. Tap water may contain contaminants and should not be used for reconstitution.","difficulty":2,"category":"Compounding","topic":"reconstitution"},
  {"id":"ptcb-1189","stem":"A patient is being discharged from the hospital on a new blood thinner. What type of document should be provided?","options":["A business card for the pharmacy","A Medication Guide","A receipt for the hospital stay","An insurance form"],"correctIndex":1,"rationale":"Patients starting new anticoagulants should receive a Medication Guide, which is an FDA-required document explaining the drug's risks, benefits, side effects, and important safety information. Anticoagulants like warfarin carry significant bleeding risk, making patient education essential for safe use.","difficulty":1,"category":"Patient Communication","topic":"discharge counseling"},
  {"id":"ptcb-1190","stem":"What is the minimum frequency for cleaning a laminar airflow workbench during compounding?","options":["Once daily","At the beginning of each shift, before each batch, every 30 minutes during continuous compounding, and after spills","Only when visibly dirty","Once weekly"],"correctIndex":1,"rationale":"Per USP <797>, the LAFW must be cleaned: at the beginning of each shift, before each batch, at least every 30 minutes during continuous compounding, after any spill, and when there is a surface contamination event. Cleaning uses sterile 70% IPA with lint-free wipes in a specific directional pattern.","difficulty":2,"category":"Sterile Products","topic":"cleaning frequency"},
  {"id":"ptcb-1191","stem":"Which of the following is true about generic drugs compared to brand-name drugs?","options":["They have different active ingredients","They must demonstrate bioequivalence to the brand product","They are always cheaper and lower quality","They don't need FDA approval"],"correctIndex":1,"rationale":"Generic drugs must demonstrate bioequivalence to the reference brand product through an ANDA (Abbreviated New Drug Application). They contain the same active ingredient, strength, dosage form, and route. They may differ in inactive ingredients, appearance, and price. They require FDA approval and meet the same quality standards.","difficulty":1,"category":"Pharmacy Operations","topic":"generic drug regulation"},
  {"id":"ptcb-1192","stem":"Which vitamin is essential for blood clotting and is the target of warfarin therapy?","options":["Vitamin A","Vitamin C","Vitamin D","Vitamin K"],"correctIndex":3,"rationale":"Vitamin K is essential for the synthesis of clotting factors II, VII, IX, and X. Warfarin works by inhibiting vitamin K epoxide reductase, preventing the recycling of vitamin K needed for clotting factor synthesis. Vitamin K (phytonadione) is the antidote for warfarin overdose.","difficulty":1,"category":"Pharmacology","topic":"vitamin K and coagulation"},
  {"id":"ptcb-1193","stem":"What is the correct way to label a compounded preparation?","options":["Handwrite the patient's name only","Include drug name, strength, quantity, BUD, lot number, storage conditions, and preparer initials","Use the original manufacturer's label","No labeling is required for compounds"],"correctIndex":1,"rationale":"Compounded preparation labels must include: drug name and strength, quantity or volume, beyond-use date (BUD), lot number, storage conditions, patient name (if patient-specific), preparer initials, and any special instructions. This ensures traceability and safe use. Both USP <795> and <797> have labeling requirements.","difficulty":1,"category":"Compounding","topic":"compounding labels"},
  {"id":"ptcb-1194","stem":"What is the brand name for the combination drug empagliflozin/metformin?","options":["Invokamet","Synjardy","Xigduo","Janumet"],"correctIndex":1,"rationale":"Synjardy contains empagliflozin/metformin (SGLT2 inhibitor + biguanide). Invokamet is canagliflozin/metformin. Xigduo is dapagliflozin/metformin. Janumet is sitagliptin/metformin. Combination diabetes products reduce pill burden and may improve adherence.","difficulty":3,"category":"Pharmacology","topic":"combination diabetes drugs"},
  {"id":"ptcb-1195","stem":"How should a pharmacy respond to a drug shortage?","options":["Stop dispensing the medication completely","Notify prescribers, identify therapeutic alternatives, and follow rationing protocols if needed","Order from any available source regardless of legitimacy","Compound a replacement without authorization"],"correctIndex":1,"rationale":"During drug shortages, pharmacies should notify prescribers of the shortage and available alternatives, check ASHP drug shortage resources, work with wholesalers to secure supply, implement rationing protocols if needed, and consider therapeutic alternatives. Obtaining drugs from unverified sources or unauthorized compounding creates safety risks.","difficulty":2,"category":"Inventory Management","topic":"drug shortage management"},
  {"id":"ptcb-1196","stem":"Which of the following is a phosphodiesterase-5 (PDE5) inhibitor?","options":["Tadalafil","Tamsulosin","Finasteride","Dutasteride"],"correctIndex":0,"rationale":"Tadalafil (Cialis) is a PDE5 inhibitor used for erectile dysfunction, BPH, and pulmonary arterial hypertension. Other PDE5 inhibitors: sildenafil (Viagra), vardenafil (Levitra). They work by increasing cGMP, causing smooth muscle relaxation. Tamsulosin is an alpha-blocker, finasteride/dutasteride are 5-alpha reductase inhibitors.","difficulty":1,"category":"Drug Classifications","topic":"PDE5 inhibitors"},
  {"id":"ptcb-1197","stem":"A medication order reads 'vancomycin 1 g IVPB q12h.' IVPB stands for:","options":["Intravenous push bolus","Intravenous piggyback","Intravenous patient bypass","Intravenous partial bolus"],"correctIndex":1,"rationale":"IVPB stands for intravenous piggyback, a secondary IV infusion connected to the primary IV line. The IVPB bag (typically 50-250 mL) is hung higher than the primary bag so it infuses first. Vancomycin IVPB is typically infused over 60-90 minutes to prevent Red Man Syndrome.","difficulty":1,"category":"Sterile Products","topic":"IV administration methods"},
  {"id":"ptcb-1198","stem":"Which medication is used to treat opioid use disorder as a long-acting monthly injection?","options":["Naloxone","Naltrexone (Vivitrol)","Methadone","Buprenorphine sublingual"],"correctIndex":1,"rationale":"Naltrexone extended-release injection (Vivitrol) is a monthly IM injection used for opioid and alcohol use disorder. It's a full opioid antagonist that blocks opioid effects. Methadone and buprenorphine SL are daily medications. Naloxone (Narcan) is for acute overdose reversal only.","difficulty":2,"category":"Pharmacology","topic":"addiction treatment"},
  {"id":"ptcb-1199","stem":"What is the proper technique for opening an ampule?","options":["Break it with bare hands","Score the neck, wrap with gauze or alcohol pad, snap away from you","Use pliers to crack it open","Hit it against the counter"],"correctIndex":1,"rationale":"To open an ampule safely: score the neck if not pre-scored, wipe with an alcohol pad, wrap the neck with gauze or an alcohol pad (for grip and to prevent cuts), and snap the top away from you in a quick motion. Use a filter needle or filter straw to withdraw contents to remove glass particles.","difficulty":1,"category":"Sterile Products","topic":"ampule technique"},
  {"id":"ptcb-1200","stem":"What does the term 'polypharmacy' refer to?","options":["Using multiple pharmacies","Taking many medications simultaneously (typically 5 or more)","A pharmacy chain with multiple locations","Compounding multiple ingredients"],"correctIndex":1,"rationale":"Polypharmacy refers to the use of multiple medications (commonly defined as 5 or more) simultaneously, particularly common in elderly patients. It increases the risk of drug interactions, adverse effects, medication non-adherence, falls, and hospitalizations. Medication reconciliation helps manage polypharmacy.","difficulty":1,"category":"Patient Safety","topic":"polypharmacy risks"},
  {"id":"ptcb-1201","stem":"A patient on warfarin starts taking a course of fluconazole. What interaction should be monitored?","options":["Decreased warfarin effect","Increased warfarin effect and bleeding risk","No interaction","Decreased fluconazole absorption"],"correctIndex":1,"rationale":"Fluconazole inhibits CYP2C9, the primary enzyme that metabolizes warfarin. This increases warfarin blood levels and INR, significantly increasing bleeding risk. The warfarin dose may need to be reduced during fluconazole therapy, and INR should be monitored closely.","difficulty":2,"category":"Drug Interactions","topic":"azole-warfarin interaction"},
  {"id":"ptcb-1202","stem":"What is the trade name for dexmethylphenidate?","options":["Adderall","Concerta","Focalin","Strattera"],"correctIndex":2,"rationale":"Dexmethylphenidate is sold as Focalin (IR) and Focalin XR (extended-release), a Schedule II stimulant for ADHD. It is the d-isomer of methylphenidate (Ritalin), thought to be the more pharmacologically active form. Concerta is methylphenidate ER, Adderall is mixed amphetamine salts.","difficulty":2,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1203","stem":"What is the purpose of adding a suspending agent to a compound?","options":["To dissolve the active ingredient","To keep insoluble particles evenly distributed throughout the liquid","To change the color","To increase potency"],"correctIndex":1,"rationale":"Suspending agents (methylcellulose, carboxymethylcellulose, Ora-Plus) increase viscosity and keep insoluble drug particles evenly distributed throughout the liquid vehicle. Without a suspending agent, particles would settle rapidly, making accurate dosing impossible. Patients must still shake before use.","difficulty":2,"category":"Compounding","topic":"suspending agents"},
  {"id":"ptcb-1204","stem":"Which of the following is NOT a valid reason for a pharmacist to refuse to fill a prescription?","options":["Suspected forgery","The prescription appears altered","The patient's race or ethnicity","Therapeutic concerns about the prescription"],"correctIndex":2,"rationale":"A pharmacist can refuse to fill a prescription for clinical or legal reasons (suspected forgery, alterations, drug interactions, inappropriate therapy), but discrimination based on race, ethnicity, gender, religion, or other protected characteristics is illegal and unethical. Pharmacies must serve all patients equitably.","difficulty":1,"category":"Regulations/Law","topic":"ethical obligations"},
  {"id":"ptcb-1205","stem":"What is the brand name for the insulin pen containing insulin aspart?","options":["Humalog KwikPen","NovoLog FlexPen","Lantus SoloStar","Levemir FlexTouch"],"correctIndex":1,"rationale":"NovoLog FlexPen contains insulin aspart, a rapid-acting insulin analog. Humalog KwikPen contains insulin lispro, Lantus SoloStar contains insulin glargine (long-acting), and Levemir FlexTouch contains insulin detemir (long-acting). Knowing insulin pen brand names is important for dispensing accuracy.","difficulty":2,"category":"Pharmacology","topic":"insulin products"},
  {"id":"ptcb-1206","stem":"What is the standard expiration date assigned to multi-dose vials once opened?","options":["24 hours","48 hours","28 days","90 days"],"correctIndex":2,"rationale":"Once opened or punctured, multi-dose vials are typically assigned a beyond-use date of 28 days per USP <797>, unless the manufacturer specifies a different timeframe. This applies even if the original expiration date is later. The date of opening should be written on the vial.","difficulty":2,"category":"Sterile Products","topic":"multi-dose vial dating"},
  {"id":"ptcb-1207","stem":"A prescription reads 'amoxicillin 500 mg cap, #30, 1 cap tid.' How many days will this prescription last?","options":["10 days","15 days","30 days","90 days"],"correctIndex":0,"rationale":"Daily consumption = 1 cap × 3 (tid = three times daily) = 3 caps/day. Day supply = 30 caps ÷ 3 caps/day = 10 days. This straightforward day supply calculation determines when the patient will need a refill.","difficulty":1,"category":"Dosage Calculations","topic":"day supply"},
  {"id":"ptcb-1208","stem":"Which of the following medications may cause QT prolongation?","options":["Acetaminophen","Azithromycin","Ibuprofen","Amoxicillin"],"correctIndex":1,"rationale":"Azithromycin can cause QT prolongation, which may lead to potentially fatal cardiac arrhythmias (torsades de pointes). Risk increases with other QT-prolonging drugs, electrolyte imbalances (hypokalemia, hypomagnesemia), and underlying cardiac conditions. The FDA issued a safety communication about this risk.","difficulty":2,"category":"Drug Interactions","topic":"QT prolongation"},
  {"id":"ptcb-1209","stem":"What is the primary function of the National Provider Identifier (NPI)?","options":["Identifies the patient","Uniquely identifies healthcare providers for billing and electronic transactions","Identifies controlled substance authority","Identifies the pharmacy location"],"correctIndex":1,"rationale":"The NPI is a unique 10-digit identifier assigned to healthcare providers (physicians, pharmacies, etc.) for use in electronic healthcare transactions. It replaced multiple provider identifiers. The NPI is different from the DEA number (controlled substances) and state license number.","difficulty":2,"category":"Pharmacy Operations","topic":"provider identifiers"},
  {"id":"ptcb-1210","stem":"Which antifungal medication is identified by the '-azole' suffix?","options":["Nystatin","Fluconazole","Terbinafine","Amphotericin B"],"correctIndex":1,"rationale":"Fluconazole (Diflucan) is an azole antifungal ('-azole' suffix), which includes fluconazole, itraconazole, voriconazole, and ketoconazole. Azoles inhibit ergosterol synthesis in fungal cell membranes. Nystatin is a polyene, terbinafine is an allylamine, and amphotericin B is also a polyene.","difficulty":1,"category":"Drug Classifications","topic":"antifungal classes"},
  {"id":"ptcb-1211","stem":"A pharmacy technician notices a discrepancy in the controlled substance count during inventory. What should be done?","options":["Adjust the count in the log and move on","Immediately notify the pharmacist-in-charge","Wait until the next inventory to recount","Assume another technician miscounted"],"correctIndex":1,"rationale":"Any discrepancy in controlled substance inventory must be immediately reported to the pharmacist-in-charge. An investigation should determine the cause (documentation error, diversion, theft). If diversion or theft is suspected, a DEA Form 106 must be filed. Adjusting counts without investigation is illegal.","difficulty":1,"category":"Regulations/Law","topic":"controlled substance discrepancies"},
  {"id":"ptcb-1212","stem":"Which of the following is a third-generation cephalosporin commonly used for serious infections?","options":["Cephalexin","Cefazolin","Ceftriaxone","Cefepime"],"correctIndex":2,"rationale":"Ceftriaxone (Rocephin) is a third-generation cephalosporin with broad gram-negative coverage, used for serious infections including meningitis, pneumonia, and gonorrhea. It's given IV/IM and has a long half-life allowing once-daily dosing. Cephalexin is first-gen, cefazolin is first-gen, and cefepime is fourth-gen.","difficulty":2,"category":"Drug Classifications","topic":"cephalosporin generations"},
  {"id":"ptcb-1213","stem":"What is the appropriate way to measure a liquid in a graduated cylinder?","options":["Fill to the top mark and pour out excess","Pour liquid to the desired mark on the cylinder, reading at the meniscus at eye level","Estimate the volume by weight","Use a beaker instead"],"correctIndex":1,"rationale":"Pour the liquid into the graduated cylinder, allowing it to settle. Read the volume at the bottom of the meniscus (curved liquid surface) at eye level. Use the smallest graduated cylinder that will contain the measured volume for greatest accuracy. A beaker is not sufficiently accurate for pharmaceutical measurements.","difficulty":1,"category":"Compounding","topic":"liquid measurement"},
  {"id":"ptcb-1214","stem":"What is the trade name for the combination drug amlodipine/atorvastatin?","options":["Caduet","Lotrel","Exforge","Vytorin"],"correctIndex":0,"rationale":"Caduet combines amlodipine (CCB for hypertension) with atorvastatin (statin for hyperlipidemia). Lotrel is amlodipine/benazepril, Exforge is amlodipine/valsartan, and Vytorin is ezetimibe/simvastatin. Combination products improve adherence by reducing pill burden.","difficulty":2,"category":"Pharmacology","topic":"combination cardiovascular drugs"},
  {"id":"ptcb-1215","stem":"A child weighs 33 lb. What is the weight in kg?","options":["10 kg","15 kg","20 kg","25 kg"],"correctIndex":1,"rationale":"To convert pounds to kilograms: 33 lb ÷ 2.2 lb/kg = 15 kg. This conversion is essential for pediatric weight-based dosing. Always verify the weight conversion before calculating pediatric doses to prevent dosing errors.","difficulty":1,"category":"Dosage Calculations","topic":"weight conversions"},
  {"id":"ptcb-1216","stem":"Which of the following is a selective serotonin reuptake inhibitor (SSRI)?","options":["Venlafaxine","Bupropion","Escitalopram","Mirtazapine"],"correctIndex":2,"rationale":"Escitalopram (Lexapro) is an SSRI used for depression and generalized anxiety disorder. Other SSRIs include sertraline, fluoxetine, paroxetine, and citalopram. Venlafaxine is an SNRI, bupropion is an NDRI, and mirtazapine is a noradrenergic/specific serotonergic antidepressant (NaSSA).","difficulty":1,"category":"Drug Classifications","topic":"antidepressant classes"},
  {"id":"ptcb-1217","stem":"What is the function of a filter needle when drawing from an ampule?","options":["To speed up the drawing process","To remove glass particles from the solution","To prevent air from entering the syringe","To add medication to the syringe"],"correctIndex":1,"rationale":"A filter needle (5-micron filter) removes glass fragments that may enter the solution when an ampule is broken open. After drawing the medication, the filter needle must be replaced with a regular needle before injecting. Alternatively, a filter straw can be used for drawing. This prevents particulate injection.","difficulty":1,"category":"Sterile Products","topic":"filter needles"},
  {"id":"ptcb-1218","stem":"Which of the following is an appropriate counseling point for patients taking bisphosphonates (e.g., alendronate)?","options":["Take with a large meal","Take on empty stomach with full glass of water, remain upright for 30 minutes","Crush the tablet for easier swallowing","Take at bedtime"],"correctIndex":1,"rationale":"Bisphosphonates must be taken first thing in the morning on an empty stomach with 6-8 oz of plain water. The patient must remain upright (sitting or standing) for at least 30 minutes and not eat/drink anything else during that time. This prevents esophageal irritation, erosion, and ulceration.","difficulty":2,"category":"Patient Communication","topic":"bisphosphonate counseling"},
  {"id":"ptcb-1219","stem":"What is the maximum number of refills allowed for a non-controlled prescription medication?","options":["5 refills","11 refills","No maximum as long as within 1 year","Unlimited refills"],"correctIndex":2,"rationale":"Non-controlled prescription medications can be refilled as many times as the prescriber authorizes, up to 1 year from the date written. After 1 year, a new prescription is required. There is no maximum number of refills for non-controlled drugs as long as the prescription is less than 1 year old.","difficulty":2,"category":"Regulations/Law","topic":"refill limitations"},
  {"id":"ptcb-1220","stem":"Which type of IV solution pulls fluid into the vascular space?","options":["Hypotonic","Isotonic","Hypertonic","All of the above"],"correctIndex":2,"rationale":"Hypertonic solutions (e.g., 3% NaCl, D10W, D5NS) have higher osmolarity than blood, pulling fluid from interstitial and intracellular spaces into the vascular space by osmosis. Isotonic solutions stay in the vascular space. Hypotonic solutions move fluid out of the vascular space into cells.","difficulty":2,"category":"Sterile Products","topic":"IV solution tonicity"},
  {"id":"ptcb-1221","stem":"A prescription requires 454 g of an ointment. How many pounds is this?","options":["0.5 lb","1 lb","2 lb","5 lb"],"correctIndex":1,"rationale":"1 pound = 454 g (approximately). Therefore, 454 g = 1 pound. This conversion is important for compounding when recipes use different measurement systems. Other useful conversions: 1 kg = 2.2 lb, 1 oz = 28.35 g.","difficulty":1,"category":"Dosage Calculations","topic":"weight conversions"},
  {"id":"ptcb-1222","stem":"Which of the following is true about the 'Do Not Crush' list?","options":["Only applies to Schedule II drugs","Includes extended-release, enteric-coated, and certain other formulations","Applies to all tablets","Only applies to hospital settings"],"correctIndex":1,"rationale":"The 'Do Not Crush' list includes extended-release (ER/XL/XR), enteric-coated (EC), sublingual, buccal, and certain other special formulations. Crushing these destroys their designed-release mechanism, potentially causing dose dumping (toxicity) or loss of efficacy. ISMP maintains a comprehensive Do Not Crush list.","difficulty":1,"category":"Medication Safety","topic":"do not crush medications"},
  {"id":"ptcb-1223","stem":"What is the generic name for Xanax?","options":["Lorazepam","Diazepam","Alprazolam","Clonazepam"],"correctIndex":2,"rationale":"Alprazolam is the generic name for Xanax, a Schedule IV benzodiazepine used for anxiety and panic disorder. Lorazepam is Ativan, diazepam is Valium, and clonazepam is Klonopin. All are benzodiazepines with varying onset, duration, and potency profiles.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1224","stem":"What is the appropriate action when a pharmacy receives a drug recall notice?","options":["Wait for the manufacturer to pick up the stock","Immediately identify affected lot numbers, pull products, notify patients who received them, and follow return procedures","Ignore if the lot numbers don't match current stock","Shred the notice"],"correctIndex":1,"rationale":"Upon receiving a recall notice: identify affected lot numbers, immediately pull and quarantine products from shelves and will-call bins, check dispensing records for patients who received affected lots, notify patients and prescribers as appropriate, and follow the manufacturer's return or destruction procedures. Document all actions.","difficulty":1,"category":"Quality Assurance","topic":"recall response procedures"},
  {"id":"ptcb-1225","stem":"Which of the following is a TNF-alpha inhibitor?","options":["Methotrexate","Hydroxychloroquine","Etanercept","Prednisone"],"correctIndex":2,"rationale":"Etanercept (Enbrel) is a TNF-alpha inhibitor (biologic DMARD) used for rheumatoid arthritis, psoriatic arthritis, and other autoimmune conditions. It works by binding TNF-alpha, reducing inflammation. Other TNF inhibitors: adalimumab (Humira), infliximab (Remicade). Methotrexate and hydroxychloroquine are conventional DMARDs.","difficulty":2,"category":"Drug Classifications","topic":"biologic DMARDs"},
  {"id":"ptcb-1226","stem":"What does the abbreviation 'PCN' refer to in pharmacy insurance?","options":["Patient Care Number","Processor Control Number","Pharmacy Certification Number","Prescription Claim Number"],"correctIndex":1,"rationale":"PCN stands for Processor Control Number, a secondary identifier on insurance cards that helps route pharmacy claims to the correct processor/plan. Along with BIN (Bank Identification Number) and Group number, PCN is essential for successful electronic claim submission.","difficulty":2,"category":"Pharmacy Operations","topic":"insurance identifiers"},
  {"id":"ptcb-1227","stem":"Which medication requires periodic CBC monitoring due to risk of agranulocytosis?","options":["Lisinopril","Clozapine","Metformin","Amlodipine"],"correctIndex":1,"rationale":"Clozapine (Clozaril) requires mandatory ANC monitoring through the Clozapine REMS due to risk of severe neutropenia/agranulocytosis. ANC must be monitored before initiation and regularly during treatment. If ANC drops below 1000/mcL, clozapine must be interrupted; below 500/mcL, it must be discontinued.","difficulty":2,"category":"Pharmacology","topic":"drug monitoring requirements"},
  {"id":"ptcb-1228","stem":"A pharmacy technician is preparing an IV admixture and notices a crack in the IV bag. What should be done?","options":["Tape over the crack","Use the bag if less than 50% has leaked","Discard the bag and obtain a new one","Infuse it faster before more leaks out"],"correctIndex":2,"rationale":"Any compromise to the integrity of an IV container (cracks, leaks, punctures) means the sterility has been breached. The bag must be discarded and not used. A new sterile bag should be obtained. Using compromised IV containers risks introducing contaminants and causing serious infections.","difficulty":1,"category":"Sterile Products","topic":"container integrity"},
  {"id":"ptcb-1229","stem":"What is the relationship between pH and drug ionization for weak acids?","options":["Lower pH increases ionization of weak acids","Higher pH increases ionization of weak acids","pH has no effect on ionization","All drugs are fully ionized at any pH"],"correctIndex":1,"rationale":"Weak acids are more ionized at higher pH (basic environment) and less ionized at lower pH (acidic environment). Non-ionized forms cross membranes more easily. This explains why aspirin (weak acid) is better absorbed in the acidic stomach where it's less ionized. This concept is key to pharmacokinetics.","difficulty":3,"category":"Pharmacology","topic":"pH and drug absorption"},
  {"id":"ptcb-1230","stem":"How many drops are in 1 mL when using a standard ophthalmic dropper?","options":["10 drops","15 drops","20 drops","25 drops"],"correctIndex":2,"rationale":"By convention, 1 mL = approximately 20 drops from a standard ophthalmic dropper. This conversion is used to calculate day supply for eye drop prescriptions. Example: A 5 mL bottle contains approximately 100 drops. Actual drop size may vary by manufacturer and formulation viscosity.","difficulty":1,"category":"Dosage Calculations","topic":"drop conversions"},
  {"id":"ptcb-1231","stem":"Which drug class is associated with the side effect of 'Purple Glove Syndrome'?","options":["Benzodiazepines","Phenytoin (IV)","Beta-blockers","ACE inhibitors"],"correctIndex":1,"rationale":"Purple Glove Syndrome is a rare but serious complication of IV phenytoin, characterized by purple discoloration, edema, and pain in the extremity where it was infused. It's caused by phenytoin's high alkalinity (pH 12) and propylene glycol vehicle. Fosphenytoin (Cerebyx) was developed to reduce this risk.","difficulty":3,"category":"Pharmacology","topic":"IV drug complications"},
  {"id":"ptcb-1232","stem":"What information should be verified when accepting a new prescription from a patient?","options":["Only the patient's name","Patient name, date of birth, address, allergies, insurance information, and the prescription itself","Only the drug name","The patient's employment status"],"correctIndex":1,"rationale":"When accepting a new prescription, verify: patient identity (name, DOB, address), current allergy list, insurance information, the prescription's completeness (drug, dose, directions, quantity, prescriber info, date, signature), and controlled substance requirements (DEA number, ID for C-II). This prevents errors from the start.","difficulty":1,"category":"Prescription Processing","topic":"prescription intake"},
  {"id":"ptcb-1233","stem":"Which of the following is a muscarinic receptor antagonist used as an inhaled bronchodilator?","options":["Albuterol","Fluticasone","Ipratropium","Montelukast"],"correctIndex":2,"rationale":"Ipratropium (Atrovent) is a short-acting muscarinic antagonist (SAMA) that blocks acetylcholine in bronchial smooth muscle, causing bronchodilation. It's used for COPD and acute bronchospasm (often combined with albuterol as DuoNeb/Combivent). Tiotropium (Spiriva) is the long-acting form (LAMA).","difficulty":2,"category":"Drug Classifications","topic":"anticholinergic bronchodilators"},
  {"id":"ptcb-1234","stem":"What is the proper disposal method for sharps used in pharmacy?","options":["Regular trash can","Sharps container (puncture-resistant, labeled)","Recycling bin","Flush down the sink"],"correctIndex":1,"rationale":"Used needles, syringes, ampules, and broken glass must be placed in designated sharps containers that are puncture-resistant, leak-proof, and clearly labeled with a biohazard symbol. Sharps containers should be sealed and disposed of by a licensed medical waste company when 3/4 full.","difficulty":1,"category":"Patient Safety","topic":"sharps disposal"},
  {"id":"ptcb-1235","stem":"Which medication is classified as an aldosterone receptor antagonist?","options":["Furosemide","Hydrochlorothiazide","Eplerenone","Chlorthalidone"],"correctIndex":2,"rationale":"Eplerenone (Inspra) is a selective aldosterone receptor antagonist (like spironolactone but more selective, with fewer anti-androgenic side effects). It's used for heart failure and post-MI. Furosemide is a loop diuretic, HCTZ and chlorthalidone are thiazide/thiazide-like diuretics.","difficulty":3,"category":"Drug Classifications","topic":"aldosterone antagonists"},
  {"id":"ptcb-1236","stem":"What is the proper technique for mixing two types of insulin in one syringe?","options":["Draw cloudy insulin first, then clear","Draw clear (regular) insulin first, then cloudy (NPH)","It doesn't matter which order","Insulin types should never be mixed"],"correctIndex":1,"rationale":"When mixing insulins: draw clear (regular) insulin first, then cloudy (NPH). Remember 'clear before cloudy.' This prevents NPH insulin from contaminating the regular insulin vial, which would alter the regular insulin's onset. Insulin glargine and detemir should NOT be mixed with other insulins.","difficulty":2,"category":"Pharmacology","topic":"insulin mixing"},
  {"id":"ptcb-1237","stem":"What is the maximum daily dose of ibuprofen for OTC use in adults?","options":["800 mg","1,200 mg","2,400 mg","3,200 mg"],"correctIndex":1,"rationale":"The maximum OTC dose of ibuprofen for adults is 1,200 mg/day (400 mg every 4-6 hours, max 3 doses). Prescription doses can go up to 3,200 mg/day for certain conditions. Higher doses increase GI bleeding, cardiovascular, and renal risks. Always use the lowest effective dose for the shortest duration.","difficulty":2,"category":"Pharmacology","topic":"OTC dosing limits"},
  {"id":"ptcb-1238","stem":"How should a pharmacy technician handle a situation where they are unsure about a drug name on a prescription?","options":["Guess based on the first few letters","Ask the patient what they think it says","Consult the pharmacist before processing","Fill it with the most common drug that looks similar"],"correctIndex":2,"rationale":"If a drug name is unclear, illegible, or unfamiliar, the technician must consult the pharmacist before processing. The pharmacist may contact the prescriber for clarification. Guessing drug names is a major cause of dispensing errors. E-prescribing has reduced but not eliminated this issue.","difficulty":1,"category":"Medication Safety","topic":"illegible prescriptions"},
  {"id":"ptcb-1239","stem":"What is the brand name for the inhaler containing budesonide/formoterol?","options":["Advair","Symbicort","Breo Ellipta","Trelegy"],"correctIndex":1,"rationale":"Symbicort contains budesonide (ICS) and formoterol (LABA) for maintenance treatment of asthma and COPD. Advair is fluticasone/salmeterol, Breo Ellipta is fluticasone/vilanterol, and Trelegy Ellipta is fluticasone/umeclidinium/vilanterol (triple therapy). Each uses different delivery devices.","difficulty":1,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1240","stem":"What is the purpose of an 'auxiliary label' on a prescription bottle?","options":["To make the bottle look more professional","To provide additional important warnings or instructions not on the main label","To identify the manufacturer","To list the ingredients"],"correctIndex":1,"rationale":"Auxiliary labels provide critical additional warnings or instructions such as 'Take with food,' 'Avoid alcohol,' 'May cause drowsiness,' 'Refrigerate,' 'Shake well,' or 'Do not crush.' They supplement the main label information and are selected based on the specific medication's properties and precautions.","difficulty":1,"category":"Prescription Processing","topic":"auxiliary labels"},
  {"id":"ptcb-1241","stem":"A patient needs Amoxicillin 250mg/5mL suspension. The prescription says 'Disp: 150mL, 5mL PO TID x 10 days'. Is the quantity appropriate?","options":["Yes, 150 mL is correct","No, only 100 mL is needed","No, 200 mL is needed","No, 250 mL is needed"],"correctIndex":0,"rationale":"Daily volume = 5 mL × 3 (TID) = 15 mL/day. Total for 10 days = 15 mL × 10 = 150 mL. The dispensed quantity of 150 mL matches the calculated requirement. This type of verification prevents over- or under-dispensing of liquid medications.","difficulty":1,"category":"Dosage Calculations","topic":"quantity verification"},
  {"id":"ptcb-1242","stem":"Which of the following is a common drug-disease interaction?","options":["Aspirin in patients with peptic ulcer disease","Acetaminophen in patients with hypertension","Amlodipine in patients with diabetes","Metformin in patients with asthma"],"correctIndex":0,"rationale":"Aspirin (and other NSAIDs) in patients with peptic ulcer disease is a significant drug-disease interaction. NSAIDs inhibit protective prostaglandins in the GI mucosa, worsening or causing ulcers and increasing GI bleeding risk. COX-2 selective NSAIDs (celecoxib) have lower GI risk but are not risk-free.","difficulty":2,"category":"Drug Interactions","topic":"drug-disease interactions"},
  {"id":"ptcb-1243","stem":"What is the trade name for sacubitril/valsartan?","options":["Diovan","Entresto","Exforge","Benicar"],"correctIndex":1,"rationale":"Entresto contains sacubitril (neprilysin inhibitor) and valsartan (ARB), used for heart failure with reduced ejection fraction (HFrEF). It showed significant mortality reduction compared to ACE inhibitors alone. Cannot be used concurrently with ACE inhibitors due to angioedema risk. 36-hour washout required.","difficulty":2,"category":"Pharmacology","topic":"heart failure drugs"},
  {"id":"ptcb-1244","stem":"How should an open multi-dose vial of insulin be stored?","options":["Freeze it for long-term storage","Store at room temperature (up to 28-30 days) or refrigerate","Return to original box in the refrigerator immediately","Store in direct sunlight for potency"],"correctIndex":1,"rationale":"Once opened, insulin vials and pens can be stored at room temperature (below 86°F/30°C) for up to 28-30 days (varies by type). Room temperature reduces injection site pain. Unopened insulin should be refrigerated. Never freeze insulin. Discard after the manufacturer's specified open-vial dating.","difficulty":2,"category":"Pharmacy Operations","topic":"insulin storage"},
  {"id":"ptcb-1245","stem":"Which controlled substance form is used to report theft or significant loss of controlled substances?","options":["DEA Form 222","DEA Form 106","DEA Form 41","DEA Form 224"],"correctIndex":1,"rationale":"DEA Form 106 is used to report theft or significant loss of controlled substances to the DEA. Form 222 is for ordering C-I/C-II substances. Form 41 is for requesting permission to destroy controlled substances. Form 224 is the DEA registration application for pharmacies.","difficulty":2,"category":"Regulations/Law","topic":"DEA forms"},
  {"id":"ptcb-1246","stem":"A suspension label says 'Shake Well.' Why is this important?","options":["It warms the medication","It activates the drug","It redistributes settled particles to ensure uniform dosing","It changes the flavor"],"correctIndex":2,"rationale":"Suspensions contain insoluble particles that settle over time (sedimentation). Shaking redistributes these particles throughout the liquid, ensuring each dose contains the correct amount of drug. Without shaking, early doses may be sub-therapeutic and later doses may contain excess drug, causing toxicity.","difficulty":1,"category":"Compounding","topic":"suspension administration"},
  {"id":"ptcb-1247","stem":"Which of the following is a disease-modifying antirheumatic drug (DMARD)?","options":["Ibuprofen","Methotrexate","Prednisone","Acetaminophen"],"correctIndex":1,"rationale":"Methotrexate is a conventional DMARD and first-line therapy for rheumatoid arthritis. It slows disease progression by modifying the immune response. NSAIDs (ibuprofen) and corticosteroids (prednisone) treat symptoms but don't modify disease course. Acetaminophen is an analgesic without anti-inflammatory properties.","difficulty":2,"category":"Drug Classifications","topic":"rheumatology medications"},
  {"id":"ptcb-1248","stem":"What does 'SL' mean as a route of administration?","options":["Subcutaneous","Sublingual","Subclavian","Submandibular"],"correctIndex":1,"rationale":"SL stands for sublingual, meaning under the tongue. Sublingual medications dissolve and are absorbed through the sublingual mucosa directly into the bloodstream, bypassing first-pass metabolism. Common sublingual medications include nitroglycerin SL tablets and buprenorphine SL film.","difficulty":1,"category":"Prescription Processing","topic":"routes of administration"},
  {"id":"ptcb-1249","stem":"A pharmacy's inventory has an annual cost of goods sold of $2,000,000 and average inventory value of $250,000. What is the turnover rate?","options":["4","6","8","10"],"correctIndex":2,"rationale":"Inventory Turnover Rate = COGS ÷ Average Inventory = $2,000,000 ÷ $250,000 = 8. The inventory turns over 8 times per year, or approximately every 45.6 days. A higher turnover rate indicates more efficient inventory management.","difficulty":2,"category":"Inventory Management","topic":"turnover calculations"},
  {"id":"ptcb-1250","stem":"Which class of drugs ends in '-triptan' and is used for migraines?","options":["Triptans (5-HT1B/1D agonists)","Tricyclic antidepressants","Antiepileptics","CGRP inhibitors"],"correctIndex":0,"rationale":"Triptans ('-triptan' suffix: sumatriptan, rizatriptan, eletriptan, etc.) are serotonin 5-HT1B/1D receptor agonists used for acute migraine treatment. They cause vasoconstriction of cranial blood vessels and inhibit pro-inflammatory neuropeptide release. Contraindicated in patients with cardiovascular disease.","difficulty":2,"category":"Drug Classifications","topic":"migraine medications"},
  {"id":"ptcb-1251","stem":"What must a pharmacy technician do before entering the buffer room for sterile compounding?","options":["Simply wash hands with regular soap","Complete full garbing procedure: remove jewelry/cosmetics, don shoe covers, hair cover, face mask, perform hand hygiene, don gown, then sterile gloves","Put on regular gloves","No preparation needed"],"correctIndex":1,"rationale":"Before entering the buffer room: remove all jewelry, cosmetics, and artificial nails. Put on shoe covers, hair cover, face mask/beard cover. Perform hand hygiene for 30+ seconds. Don a non-shedding gown. Apply sterile gloves after hand sanitization in the buffer room. This ordered procedure minimizes microbial contamination.","difficulty":2,"category":"Sterile Products","topic":"garbing requirements"},
  {"id":"ptcb-1252","stem":"What is the relationship between half-life and steady state?","options":["Steady state is reached after 1 half-life","Steady state is reached after 4-5 half-lives","Steady state is immediate with the first dose","Half-life has no relationship to steady state"],"correctIndex":1,"rationale":"Steady state (where drug input equals drug elimination) is reached after approximately 4-5 half-lives of consistent dosing. For example, if a drug has a 12-hour half-life, steady state is reached in about 48-60 hours. This concept determines how long it takes for a drug to reach its full therapeutic effect.","difficulty":3,"category":"Pharmacology","topic":"pharmacokinetics"},
  {"id":"ptcb-1253","stem":"Which of the following is an example of a medication error prevention strategy?","options":["Relying on memory for drug information","Independent double-check for high-alert medications","Rushing to fill prescriptions quickly","Using unapproved abbreviations"],"correctIndex":1,"rationale":"Independent double-checks involve two practitioners independently verifying critical steps (drug, dose, patient, route, rate) for high-alert medications. Other prevention strategies include barcode scanning, tall man lettering, forcing functions, automated dispensing, and a just culture that encourages error reporting.","difficulty":1,"category":"Medication Safety","topic":"error prevention strategies"},
  {"id":"ptcb-1254","stem":"What is the brand name for desvenlafaxine?","options":["Effexor","Cymbalta","Pristiq","Fetzima"],"correctIndex":2,"rationale":"Desvenlafaxine is sold as Pristiq, an SNRI antidepressant. It is the active metabolite of venlafaxine (Effexor). Cymbalta is duloxetine, and Fetzima is levomilnacipran. All are SNRIs but differ in specificity, side effect profiles, and indications.","difficulty":2,"category":"Pharmacology","topic":"brand-generic pairs"},
  {"id":"ptcb-1255","stem":"A compounding recipe requires 'qs ad 100 mL.' What does 'qs ad' mean?","options":["Quantity sufficient to add","Quantity sufficient to make (add enough to reach the final volume)","Quick shake and dissolve","Quality standard adjusted"],"correctIndex":1,"rationale":"'qs ad' (quantum sufficit ad) means 'a sufficient quantity to make' the final volume. 'qs ad 100 mL' means add enough vehicle to bring the total volume to 100 mL. First add all ingredients, then bring to final volume with the vehicle. This ensures the correct final concentration.","difficulty":2,"category":"Compounding","topic":"compounding abbreviations"}
];
